import{t as e}from"./rolldown-runtime-H_PjY6_i.js";var i=e({A0001:()=>t,default:()=>n}),t={title:"Human Verification Technology",definition:"Also known as CAPTCHA or verification code mechanism, it distinguishes human operations from non-human operations by presenting challenges.",description:"Challenges are typically presented through behavioral CAPTCHAs, image-text CAPTCHAs, or by collecting and analyzing data such as mouse movement trajectories, click events, screen touch pressure, swipe trajectories, request access rates, and 3D gyroscope readings. Note: facial recognition is generally considered a form of biometric identification (A0023).",limitation:"The black-gray industry has given rise to 'CAPTCHA-solving platforms' (AT0008), which use crowdsourced human labor to complete human verification challenges. This is a dimensionality-reduction attack against human verification, and in theory can render all explicit human verification completely ineffective.",references:[{title:"OAT-009 CAPTCHA Defeat - OWASP",link:"https://owasp.org/www-project-automated-threats-to-web-applications/assets/oats/EN/OAT-009_CAPTCHA_Defeat"},{title:"NIST SP 800-63B: Digital Identity Guidelines - Authentication and Lifecycle Management"}],keywords:["Human Verification Technology","CAPTCHA","anti-bot verification","bot check","human check","challenge-response","verification challenge"]},n={A0001:t,"A0001-001":{title:"Image-Text CAPTCHA",definition:"A type of human verification challenge where the challenger must identify the content in an image and enter it into an input field.",description:"Image CAPTCHAs, also known as graphic CAPTCHAs, are a common user identity verification method. They typically consist of a set of randomly generated numbers, letters, or symbols displayed in graphical form, usually with interference elements such as lines, noise, or distortion to prevent automated tools (e.g., bots or OCR software) from easily recognizing them. Users must correctly enter the characters shown in the image to pass verification. This method is primarily used to prevent malicious software or non-human users from performing automated operations. The challenge mainly relies on the gap between human ability to recognize irregular image text and computer recognition ability.",limitation:"As computer processing power improves and AI image recognition capabilities advance, the probability of this type of CAPTCHA being cracked is increasing. In particular, the development of AI-generated content has rendered traditional image CAPTCHA mechanisms nearly ineffective. A mainstream evolution direction for image CAPTCHAs is to combine them with behavioral CAPTCHAs (A0001-002), using multi-dimensional factors to complete the human verification challenge.",references:[{title:"Captcha open-source libraries on GitHub"}],keywords:["Image-Text CAPTCHA","image CAPTCHA","graphic CAPTCHA","text CAPTCHA","OCR CAPTCHA","image verification","image-text challenge"]},"A0001-002":{title:"Behavioral CAPTCHA",definition:"A human verification mode that combines image-text recognition with human mouse/keyboard and screen interaction.",description:"Common behavioral CAPTCHAs are built on the basis of human recognition of image-text information, requiring actions such as clicking, selecting, sliding, and dragging. They judge human vs. machine by comparing the differences between human behavior and machine behavior. Because image recognition is supplemented by behavioral identification, resistance to cracking is higher than traditional image CAPTCHAs (A0001-001).",limitation:"The principle of behavioral CAPTCHAs is to perform certain keyboard/mouse actions based on understanding of image-text information. As seen from the limitations of image CAPTCHAs (A0001-001), the challenge of distinguishing humans from machines through image-text is becoming increasingly difficult. Behavioral CAPTCHAs use deep learning on human keyboard/mouse actions to form models that identify the smooth automated keyboard/mouse operations of machines. However, automated machines can also use deep learning on human keyboard/mouse actions to achieve convincing imitation, which will be a major challenge in the future.",references:[{title:"AJ-Captcha (behavioral CAPTCHA, including sliding puzzle and text click-selection)"}],keywords:["Behavioral CAPTCHA","slider CAPTCHA","sliding puzzle CAPTCHA","click CAPTCHA","interaction CAPTCHA","behavior-based verification","human behavior verification"]},"A0001-003":{title:"Voice CAPTCHA",definition:"A human verification technology similar to image CAPTCHAs but using audio for verification. Users must listen to system-generated voice content and then answer or perform related operations to prove they are a real human user. Voice CAPTCHAs are commonly used in phone verification, voice navigation systems, and other scenarios requiring voice interaction.",description:"Methods include: digit string verification — the system generates a voice string containing numbers, and the user must listen and enter the correct digit string to complete verification. Voice commands — the user may be asked to follow voice prompts to perform certain instructions, such as saying specific words, numbers, or performing an action. Speech recognition technology — the voice CAPTCHA system may use speech recognition to confirm whether the user's answer is correct.",limitation:"The limitations of voice CAPTCHAs include sensitivity to voice quality, differences in user comprehension, noisy environments, unfriendliness to users with disabilities, and potentially increased computational resource requirements.",references:[{title:"Digital Identity Guidelines: Authentication and Lifecycle Management - NIST SP 800-63B",link:"https://pages.nist.gov/800-63-3/sp800-63b.html"}],keywords:["Voice CAPTCHA","audio CAPTCHA","speech CAPTCHA","voice verification challenge","audio verification","speech challenge"]},"A0001-004":{title:"Silent CAPTCHA",definition:"A human verification technology that analyzes the user's behavioral characteristics to determine whether the user is a real human. Silent CAPTCHA does not require the user to perform any additional operations or actively input any information to complete verification.",description:"Methods include: user behavior analysis — analyzing behavioral characteristics such as mouse movement trajectories, click events, screen touch pressure, swipe trajectories, request access rates, and 3D gyroscope data to determine whether the user is a real human. User environment analysis — analyzing environmental characteristics such as IP address, device information, browser information, operating system information, and geographic location to determine whether the user is a real human. Combined behavior and environment analysis — analyzing both behavioral and environmental characteristics together to determine whether the user is a real human.",limitation:"The limitations of silent CAPTCHA include sensitivity to the user's environment and unfriendliness to users with disabilities.",references:[{title:"OWASP Automated Threats to Web Applications",link:"https://owasp.org/www-project-automated-threats-to-web-applications/"}],keywords:["Silent CAPTCHA","invisible CAPTCHA","passive CAPTCHA","background verification","risk-based verification","frictionless bot detection"]}},a=e({A0002:()=>o,default:()=>s}),o={title:"API Signature Verification",definition:"Performing integrity signing and verification on interface requests.",description:"Also known as interface signature verification or request signing. Because client-side data integrity cannot be guaranteed, hashing the request data and re-verifying it on the server side can ensure the data has not been tampered with. Note: data integrity is closely tied to the strength of the hashing algorithm — weak algorithms like MD5 are no longer sufficient to guarantee integrity. Additionally, API signatures are increasingly used in automated request detection and countermeasures. Strictly speaking, API signatures themselves do not have human verification capability; the current focus is on the complexity and concealment of custom signing algorithms, such as client application hardening (A013), data hiding (A039), algorithm whitebox protection, dynamic keys, WebAssembly, etc.",limitation:"API signatures are fine for ensuring data integrity during transmission, but because they are widely used to prevent automation, they face strong adversarial pressure. Since the signing algorithm must exist in some form on the client side, it is effectively visible to the user. Attackers can break the signing algorithm by parsing the algorithm, calling the signing interface, simulating clicks, etc., enabling automated forgery of requests.",references:[{title:"smart-cloud - an open-source Spring Cloud scaffold with API signing capability"}],keywords:["API Signature Verification","request signing","API signing","interface signature verification","HMAC signature","payload signing","request integrity verification"]},s={A0002:o},r=e({A0003:()=>c,default:()=>l}),c={title:"Cloud-Side Anti-Crawling",definition:"Identifying and restricting crawler requests on the server side based on terminal request characteristics and access frequency.",description:"Also known as cloud-side crawler identification. Broadly speaking, any capability for human-machine identification or automated request detection falls under the scope of crawler identification. Here we use a narrow definition: the ability to identify high-frequency automated requests on the server side based on terminal request characteristics, user identity, and access frequency. Terminal request characteristics include but are not limited to: device fingerprinting and terminal tracking (A021), request IP and HTTP header information, etc. Terminal request characteristics combined with user identity enable unique identification of the requesting endpoint; combined with server-side algorithms and rate/count limits per unit time, this enables identification and restriction of high-frequency automated requests.",limitation:"Crawler identification depends on three prerequisites: 1. unique identification of the requester, 2. identity identification of the requester, 3. request frequency calculation. All three are necessary. Without effective unique identification, detection can be bypassed by changing IP, UA, or device fingerprint. Without identity identification, good crawlers (search engines) cannot be distinguished from bad ones. Without frequency calculation, effective blocking is impossible. All three prerequisites have limitations: terminal and identity identification not tied to accounts can be forged; account-based identity identification can be countered by bulk registration (R0030-001); if identity is identified by request characteristics, those can be forged; request frequency can be bypassed by slow-rate crawling. Additionally, crawler identification has inherent latency, making it unable to identify and prevent scenarios like last-second bidding (R0003-001) and auction sniping (R0003-002) in real time. Therefore, crawler identification alone cannot solve the problem of automated requests; it must be combined with other countermeasures.",references:[{title:"Introduction to Crawlers and Anti-Crawling Techniques (see Chapter 2 - Anti-Crawling Technologies)"}],keywords:["Cloud-Side Anti-Crawling","anti-crawling","crawler detection","anti-scraping","bot detection","web scraping defense","anti-bot"]},l={A0003:c},d=e({A0004:()=>u,default:()=>m}),u={title:"Rate Limiting",definition:"Controlling the access frequency when a visitor requests related resources.",description:"Rate limiting can be used in scenarios such as traffic peak shaving. Its purpose is to relieve server pressure. For crawler scenarios with extremely high-frequency data requests far exceeding normal human request rates, it has a relatively direct blocking effect, preventing traffic far exceeding server capacity from causing denial of service and cascading failures.",limitation:"Unlike crawler identification (A003), rate limiting does not strictly distinguish between human traffic and automated traffic. This means that a threshold set too low will mistakenly block some legitimate human requests, while a threshold set too high will let through low-frequency crawlers. Therefore, it cannot be considered an effective crawler identification and blocking measure.",references:[{title:"API4:2019 Lack of Resources & Rate Limiting - OWASP API Security ..."}],keywords:["Rate Limiting","throttling","API rate limiting","request rate control","traffic shaping","request throttling","burst control"]},m={A0004:u},h=e({A0005:()=>g,default:()=>p}),g={title:"Quantity Limiting",definition:"Controlling the total number of accesses when a visitor requests related resources.",description:"Quantity limiting is similar to rate limiting (A004), but its control point is primarily on the total number of resource requests over a longer period of time. Rate limiting controls the number of accesses within a short time window without limiting the total over a longer period. For example, SMS verification code request interfaces typically apply both per-unit-time rate limits and total request limits per hour or day based on identifiers such as IP, phone number, or user ID — both to prevent malicious resource consumption and to prevent verification code abuse and SMS bombing.",limitation:"Quantity limiting is a relatively broad loss-reduction measure: it allows losses or risks to occur but with a certain tolerance. When the unique identity of the requester cannot be accurately identified, the effect is poor. For example, malicious SMS consumption (R0029) and CC attacks (R0029-001) can achieve sustained abuse by continuously changing IPs. If total limits are applied without distinguishing requester identity, normal users will be affected — for example, some cloud services limit total daily request traffic and block all requests once the limit is exceeded.",references:[{title:"Authorization Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html"},{title:"Blocking Brute Force Attacks - OWASP"}],keywords:["Quantity Limiting","quota","usage limit","daily limit","count cap","attempt limit","request cap"]},p={A0005:g},f=e({A0006:()=>y,default:()=>b}),y={title:"Malicious Content Detection",definition:"Identifying malicious content in user-generated content.",description:"User-generated content (UGC) includes but is not limited to: text, images, video (streams), links, etc. Malicious content varies by interest and scenario and includes but is not limited to: illegal content, violations, fraud, malicious promotion, etc. Simple text detection can be achieved by setting keywords; complex text content may also involve natural language processing. For image or video content, in addition to OCR text recognition, image content recognition is also required. For links, beyond blacklists and whitelists, some scenarios also require combining domain and link threat intelligence (A016-002) for more precise identification.",limitation:"Malicious content detection is mostly based on keyword matching or scoring mechanisms from some type of strategy model, which allows attackers to counter detection through keyword bypasses, model bypasses, or borderline scoring techniques.",references:[{title:"Provisions on the Governance of the Online Information Content Ecosystem",link:"https://www.cac.gov.cn/2019-12/20/c_1578375159509309.htm"}],keywords:["Malicious Content Detection","content moderation","UGC moderation","harmful content detection","abuse detection","trust and safety","policy enforcement"]},b={A0006:y,"A0006-001":{title:"Manual Content Review",definition:"Reviewing user-generated content for compliance through human review.",description:"Manual review is most commonly used for reviewing images, videos, and video streams, or to supplement automated machine identification with stronger judgment.",limitation:"Due to human resource and efficiency constraints, multi-account, large-scale automated requests can be used to achieve a denial-of-service attack against human reviewers. This can result in prolonged downtime for pre-publication review, or significantly extended response times for post-publication removal of malicious content.",references:[{title:"Provisions on the Governance of the Online Information Content Ecosystem",link:"https://www.cac.gov.cn/2019-12/20/c_1578375159509309.htm"}],keywords:["Manual Content Review","human review","manual moderation","content moderation review","trust and safety review"]},"A0006-002":{title:"Automated Malicious Image Detection",definition:"Identifying malicious image content in user-generated content.",description:"Malicious image detection generally consists of two parts: first, OCR recognition of text within the image followed by malicious text detection (A006-001); second, recognition of the visual content of the image itself, such as pornography or violence, which typically requires machine image recognition algorithms.",limitation:"Current OCR text recognition accuracy is relatively high, but it is still subject to the limitations of automated malicious text detection (A006-001). Recognizing image content itself currently has a low accuracy rate and needs to be combined with manual content review (A006-007).",references:[{title:"Artificial Intelligence Risk Management Framework - NIST AI 100-1",link:"https://www.nist.gov/itl/ai-risk-management-framework"},{title:"Tesseract OCR Documentation",link:"https://tesseract-ocr.github.io/"}],keywords:["Automated Malicious Image Detection","image moderation","visual moderation","image abuse detection","image safety","OCR filtering"]},"A0006-003":{title:"Automated Malicious Audio Detection",definition:"Identifying malicious audio content in user-generated content.",description:"Malicious audio detection should also consist of two parts: first, speech recognition to convert speech to text, followed by malicious text detection (A006-001); second, recognition of the content conveyed by the audio, such as pornography or violence.",limitation:"Attackers can use adversarial samples to fool automated malicious audio detection systems, preventing them from accurately detecting and identifying malicious audio. Additionally, automated malicious audio detection systems may be affected by environmental noise, language variation, speaker variation, and other factors, reducing their accuracy.",references:[{title:"Speaker Recognition Evaluation - NIST",link:"https://www.nist.gov/itl/iad/mig/speaker-recognition"}],keywords:["Automated Malicious Audio Detection","audio moderation","voice moderation","audio abuse detection","audio safety detection"]},"A0006-004":{title:"Automated Malicious Video Detection",definition:"Identifying malicious video content in user-generated content.",description:"The current general approach to malicious video detection is to extract key frames as images and then perform malicious image detection (A006-002), and to extract the audio track for automated malicious audio detection (A006-003). With the development of AI-generated content, multi-modal large models have gained the ability to understand video content, and detection effectiveness is being significantly improved.",limitation:"This is equally subject to the limitations of automated malicious image detection (A006-002) and automated malicious audio detection (A006-003).",references:[{title:"TRECVID - NIST",link:"https://www-nlpir.nist.gov/projects/trecvid/"}],keywords:["Automated Malicious Video Detection","video moderation","stream moderation","video abuse detection","video safety detection"]},"A0006-005":{title:"Automated Malicious Link Detection",definition:"Identifying malicious links in user-generated content.",description:"There are currently two mainstream approaches to handling links: whitelist mode and blacklist mode. Blacklist mode typically needs to be combined with domain and link threat intelligence (A016-002).",limitation:"Whitelist-based domain auditing is ineffective against open redirect vulnerabilities and resource abuse (R0069). Blacklist-based auditing has the problem that domains or links can easily be changed. Therefore, in many cases neither approach works well.",references:[{title:"Phishing Guidance - CISA",link:"https://www.cisa.gov/topics/cyber-threats-and-advisories/types-cyber-threats/phishing"},{title:"An effective detection approach for phishing websites using URL and HTML features"}],keywords:["Automated Malicious Link Detection","malicious URL detection","phishing URL detection","URL reputation","link scanning","safe browsing"]},"A0006-006":{title:"Automated Malicious Document Detection",definition:"Identifying malicious documents in user-generated content.",description:"Malicious document detection is carried out in two aspects: first, document content recognition — extracting document content and then performing malicious text detection (A006-001) and malicious image detection (A006-002); second, antivirus detection of the document itself, which typically requires integration with antivirus software.",limitation:"Attackers can use adversarial samples to fool automated malicious document detection systems, preventing them from accurately detecting and identifying malicious documents. Additionally, automated malicious document detection systems may be affected by changes in file format, language, font, and other factors, reducing their accuracy.",references:[{title:"Analyze Malicious Office Documents: The Complete Guide"}],keywords:["Automated Malicious Document Detection","malicious document scanning","office document security","macro malware detection","document safety scanning","file inspection"]},"A0006-007":{title:"Automated Malicious Text Detection",definition:"Identifying malicious text content in user-generated content.",description:"Simple text detection is typically built on a blacklist of keywords; complex text detection combines deep learning with sentiment analysis of the text.",limitation:"Due to the diversity and ambiguity of language, and the widespread existence of homophones, near-homophones, and visually similar characters in Chinese, it is very easy to bypass automated malicious text detection and produce malicious text that preserves the original meaning. A classic example is 'Martian script' (a form of obfuscated Chinese text), and there are many other methods such as using pinyin initials as substitutes. Therefore, in some necessary or extreme scenarios, manual content review (A006-007) needs to be introduced as a supplement.",references:[{title:"Leveraging NLP Techniques for Effective Content Moderation"}],keywords:["Automated Malicious Text Detection","text moderation","NLP moderation","harmful text detection","spam text detection","content filtering"]},"A0006-008":{title:"Automated AI-Generated Content Detection",definition:"Identifying whether user-generated content was produced by AI.",description:"Technologies for detecting AI-generated content (AIGC detection) include: grammatical and logical analysis, semantic consistency detection in text; texture structure detection, frequency domain feature analysis, generation artifact detection in images; spectral feature analysis and voiceprint consistency detection in audio; inter-frame consistency detection and deepfake detection in video. Deep learning models such as convolutional neural networks and multi-modal detection models are widely applied. Since 2025, multi-modal AI detection technology has achieved an average accuracy rate of over 90% for videos generated by mainstream models, but as generative models continue to evolve, the adversarial battle between detection and generation continues to escalate.",limitation:"These methods face the challenge that advanced generative models are increasingly approaching realistic expression, and traditional rule-based and pattern detection approaches may be insufficient to distinguish generated from real content. Deepfake technology continues to evolve, and adversarial samples can fool detection systems. Additionally, while AI-generated content labeling requirements (such as China's requirement for explicit labeling of AI-generated videos starting September 2025) provide supplementary judgment, content from non-compliant platforms remains difficult to identify.",references:[{title:"iResearch & NetEase Yidun Release Industry First Digital Content Risk Control White Paper"}],keywords:["Automated AI-Generated Content Detection","AI content detection","synthetic content detection","AI-generated text detection","AI-generated image detection","deepfake detection"]}},v=e({A0007:()=>w,default:()=>k}),w={title:"Multi-Factor Authentication",definition:"Adding additional identity verification factors beyond the primary identification method (such as username and password).",description:"Multi-Factor Authentication (MFA), sometimes also called two-factor authentication, has become the mainstream approach to identity verification. Its existence largely addresses the problem of identity impersonation and abuse caused by credential leaks. Common MFA factors include: SMS verification codes, email verification codes, Time-based One-Time Passwords (TOTP), etc.",limitation:"Compared to traditional username/password login, MFA can significantly improve account security. However, attacks against MFA are also constantly emerging, such as Man-in-the-Middle (MitM) attacks, SIM swap attacks, Pass-The-Cookie attacks, MFA fatigue attacks, etc., which to some extent undermine the account security framework built by MFA.",references:[{title:"Multifactor Authentication Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Multifactor_Authentication_Cheat_Sheet.html"},{title:"NIST SP 800-63B: Digital Identity Guidelines - Authentication and Lifecycle Management"}],keywords:["Multi-Factor Authentication","MFA","2FA","two-factor authentication","two-step verification","step-up authentication"]},k={A0007:w,"A0007-001":{title:"SMS Verification",definition:"Sending a verification code to the user's phone via SMS; the user enters the code to complete identity verification.",description:"SMS verification codes are currently the most common form of multi-factor authentication. Their advantages include: 1. The user's phone number is unique and can serve as a unique identifier; 2. SMS verification codes are one-time use with a short validity period, effectively preventing identity impersonation and abuse from code leaks during the validity window; 3. SMS verification codes are a mandatory verification method that users cannot bypass.",limitation:"Because SMS verification codes are sent to the user's phone via SMS, the code may be leaked during the sending process by the SMS service provider or during the phone's receipt process, leading to identity impersonation and abuse. Additionally, since SMS verification codes rely on phone numbers, and users may change their phone numbers, the new holder of a phone number may gain access to the previous holder's account. Furthermore, SMS verification codes are also subject to SMS bombing (R0029).",references:[{title:"SMS OTP (One-Time Password) Verification: Quick Start Guide"}],keywords:["SMS Verification","SMS OTP","text message verification","SMS code","phone verification code"]},"A0007-002":{title:"Email Verification",definition:"Sending a verification code to the user's email address; the user enters the code to complete identity verification.",description:"Email verification codes are similar to SMS verification codes. Their advantages include: 1. The user's email address is unique and can serve as a unique identifier; 2. Email verification codes are one-time use with a short validity period, effectively preventing identity impersonation and abuse from code leaks during the validity window; 3. Email verification codes are a mandatory verification method that users cannot bypass.",limitation:"Because registering an email address is relatively easy, using email verification codes to defend against bulk registration (R0030-001) is less effective. Additionally, many email services do not require multi-factor authentication for login, meaning that even if email verification codes are used, identity impersonation and abuse cannot be prevented if the user's credentials are leaked.",references:[{title:"Multi-Factor Authentication - Wikipedia"}],keywords:["Email Verification","email OTP","email code","email confirmation","mailbox verification"]},"A0007-003":{title:"One-Time Password",definition:"A time-based one-time password generated by the TOTP algorithm; the user enters the password to complete identity verification.",description:"TOTP is a time-based one-time password. Its advantages include: 1. TOTP is one-time use with a short validity period, effectively preventing identity impersonation and abuse from password leaks during the validity window; 2. TOTP is a mandatory verification method that users cannot bypass.",limitation:"Because TOTP is generated by the TOTP algorithm which is time-based, the security of TOTP depends on time synchronization. If the server time and the user's terminal time are out of sync, the TOTP-generated password will be incorrect.",references:[{title:"Nearly 1,000 Data Breaches in Q1 2023, Affecting 1,204 Companies Across 38 Industries"}],keywords:["One-Time Password","OTP","one-time code","passcode","verification code","TOTP","HOTP"]},"A0007-004":{title:"Phone Voice Verification",definition:"A human verification technology conducted via phone call. After receiving the call, the user must complete a verification challenge, typically by responding to a system-generated voice prompt or performing a related operation. This verification method is commonly used for account identity verification, password resets, and other sensitive operations to improve security.",description:"Methods include: digit string verification — after the user answers the call, the system plays a voice string containing numbers, and the user must listen and enter the correct digit string to complete verification. Voice commands — the user may be asked to follow voice prompts to perform certain instructions, such as saying specific words, numbers, or performing an action. Speech recognition technology — the voice verification system may use speech recognition to confirm whether the user's response is correct.",limitation:"The limitations of phone voice verification codes include sensitivity to voice quality, differences in user comprehension, confidentiality concerns, unfriendliness to users with disabilities, and potential risks of abuse.",references:[{title:"Digital Identity Guidelines: Authentication and Lifecycle Management - NIST SP 800-63B",link:"https://pages.nist.gov/800-63-3/sp800-63b.html"}],keywords:["Phone Voice Verification","voice verification","voice OTP","call verification","IVR verification"]},"A0007-005":{title:"Passkeys / Phishing-Resistant Authentication",definition:"A phishing-resistant authentication method based on FIDO2, WebAuthn, and passkey standards that uses public-key cryptography and relying-party binding to reduce reusable credential theft.",description:"Passkeys replace reusable passwords or one-time codes with asymmetric keys. During registration, an authenticator creates a key pair, keeps the private key on a device, security key, or platform authenticator, and stores only the public key on the server. During sign-in, the authenticator verifies the legitimate domain and signs the challenge. This reduces phishing, credential stuffing, MFA fatigue, and adversary-in-the-middle code theft risks for account login, administrator access, and high-risk transaction confirmation.",limitation:"Passkeys do not prevent session hijacking after an active session cookie, device token, or endpoint is stolen by malware. Cross-device sync, account recovery, device loss, and compatibility require supporting processes. High-risk services should combine passkeys with device binding, session risk controls, anomaly detection, and step-up authorization.",references:[{title:"More than a Password - CISA"},{title:"CISA Secure by Demand Guide: Phishing-Resistant Authentication"}],keywords:["Passkeys / Phishing-Resistant Authentication","passkeys","phishing-resistant auth","passwordless login","FIDO2","WebAuthn","anti-phishing MFA"]}},A=e({A0008:()=>S,default:()=>P}),S={title:"Improving Service Availability",definition:"Improving the number of concurrent terminal requests that can be handled by filtering traffic and increasing server computing resources.",description:"Improving service availability is a systematic engineering effort. On one hand, it requires identifying and blocking malicious traffic; on the other hand, it requires addressing system bottlenecks and improving response efficiency.",limitation:"Cost issues: improving service availability requires significant investment in human, material, and financial resources, which may increase enterprise costs. Technical issues: in some cases, technical limitations may affect service availability — for example, some applications may not be able to seamlessly switch between multiple data centers. Human factors: human factors may also affect service availability, such as human error and malicious attacks.",references:[{title:"High Availability - Wikipedia"}],keywords:["Improving Service Availability","high availability","uptime improvement","service resilience","fault tolerance","service continuity"]},P={A0008:S,"A0008-001":{title:"Adding Computing Resources",definition:"Improving the number of concurrent terminal requests that can be handled by adding server computing resources.",description:"For distributed architectures, adding computing resources is the simplest and most effective way to improve availability.",limitation:"This is complementary to business system optimization (A008-004). Adding computing resources can quickly resolve availability issues but will significantly increase operating costs.",references:[{title:"Auto Scaling - Wikipedia"}],keywords:["Adding Computing Resources","autoscaling","horizontal scaling","capacity scaling","scale out","elastic scaling"]},"A0008-002":{title:"DDoS Protection",definition:"Identifying and filtering attack traffic through a DDoS protection system.",description:"Filtering attack traffic through a DDoS protection system allows fewer, more legitimate user requests to be served by the server. This is an effective approach when the system is under large-scale attack.",limitation:"Existing DDoS protection systems have limited effectiveness against CC attacks and need to be combined with cloud-side anti-crawling (A003) and other measures.",references:[{title:"Denial of Service Attack - Wikipedia"}],keywords:["DDoS Protection","DDoS mitigation","anti-DDoS","traffic scrubbing","volumetric attack defense","L7 DDoS protection"]},"A0008-003":{title:"Front-End CDN",definition:"Configuring a CDN in front of resource access to achieve caching and acceleration of static resources.",description:"Dynamic-static separation is a common method for improving server response efficiency. For situations where dynamic-static separation cannot be implemented or where static resource load is high, a front-end CDN can effectively relieve server pressure and improve response efficiency.",limitation:"Caching acceleration is effective for static resources but does not help with dynamic resources.",references:[{title:"What is Amazon CloudFront? - AWS Documentation",link:"https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/Introduction.html"}],keywords:["Front-End CDN","CDN","content delivery network","edge caching","static asset delivery","web acceleration"]},"A0008-004":{title:"Business System Optimization",definition:"Optimizing the business system to improve response efficiency and reduce resource consumption.",description:"Reducing the system load of business requests by streamlining processes, setting up caches, optimizing algorithms, increasing concurrency, and adjusting architecture — thereby reducing response time and increasing request throughput.",limitation:"Has a long implementation cycle; suitable for long-term planning but not a quick fix. Requires significant R&D investment.",references:[{title:"Business Continuity - Wikipedia"}],keywords:["Business System Optimization","system optimization","performance tuning","process optimization","throughput improvement","latency reduction"]},"A0008-005":{title:"Increasing Business Resources",definition:"Addressing resource scarcity to some extent by increasing the available business resources.",description:"For example, increasing the number of products, quota slots, adding more shifts, flights, etc.",limitation:"For resources that can yield high returns, it is difficult to directly solve resource scarcity by simply increasing supply.",references:[{title:"Cloud Computing - Wikipedia"}],keywords:["Increasing Business Resources","capacity expansion","resource scaling","inventory expansion","quota increase","staffing increase"]}},T=e({A0009:()=>I,default:()=>C}),I={title:"Time Limiting",definition:"Controlling related resources so they are only valid within a certain time window.",description:"A typical scenario for time limiting is SMS verification code sending: by limiting the interval between code sends, it prevents SMS bombing against a specific phone number. Time limits are also commonly applied in scenarios such as password brute-forcing and payment password errors to prevent account compromise and financial loss. Time limiting is sometimes also applied to user content posting scenarios to prevent content bombing or to slow down the pressure from automated requests.",limitation:"Time limiting is generally a 'business-impacting' countermeasure that has some effect on normal user requests or services. Therefore, a compromise value is usually chosen that is acceptable to normal users while maximally blocking attackers.",references:[{title:"Rate Limiting - Wikipedia"}],keywords:["Time Limiting","time window limit","cooldown period","send interval limit","expiry window","temporal rate limiting"]},C={A0009:I},x=e({A0010:()=>D,default:()=>q}),D={title:"Terminal Abnormal Environment Detection",definition:"Identifying the application runtime environment and user request environment to detect anomalies.",description:"Abnormal environment detection works by collecting, analyzing, and evaluating dozens of data points including but not limited to: terminal silent human verification challenges, application legitimacy, process legitimacy, whether the device is rooted/jailbroken, gyroscope status, and whether plugins are installed. In business scenarios, abnormal environment detection is generally implemented through the business terminal access system. Depending on the business access mode, the terminal access system may be a browser, a mobile APP, a desktop application, etc. Abnormal environment detection capability is heavily dependent on the permissions of the business terminal access system. Due to user authorization restrictions and legal/regulatory constraints, abnormal environment detection has certain limitations and is also constrained by adversarial countermeasures and terminal data integrity.",limitation:"Because abnormal environment detection is carried out on a user-controlled terminal, the ultimate effectiveness depends on the adversarial contest. In theory, since the terminal is controllable, it is always possible to bypass various abnormal environment detection strategies — it is ultimately a matter of time cost and capability.",references:[{title:"Device Fingerprint - Wikipedia"}],keywords:["Terminal Abnormal Environment Detection","device fingerprinting","anomaly detection","device environment check","abnormal device detection","terminal environment detection"]},q={A0010:D,"A0010-001":{title:"Emulator Detection",definition:"Identifying whether an APP is running on a mobile phone emulator.",description:"Emulators are often used for fraudulent order manipulation. Accurately identifying emulators has become an important module in app development, and there are now specialized companies providing SDKs for developers to detect emulators. Currently popular Android emulators fall into roughly two categories: those based on QEMU and those based on Genymotion (VirtualBox-type). Common detection methods include: checking whether the IMEI is all zeros (0000000000 format); checking for emulator-specific values in the Build properties; matching QEMU-specific feature files and properties; obtaining CPU information and filtering out x86 (real devices are generally ARM-based), etc.",limitation:"There are two countermeasure points for mobile emulator detection: one is to pre-forge the information collected by the APP; the other is to forge the information after the APP has collected and uploaded it.",references:[{title:"MASTG-KNOW-0031: Emulator Detection - OWASP",link:"https://mas.owasp.org/MASTG-KNOW-0031/"}],keywords:["Emulator Detection","emulator check","Android emulator detection","virtual device detection","QEMU detection","Genymotion detection"]},"A0010-002":{title:"Cloud Phone Detection",definition:"Identifying whether an APP is running on a cloud phone.",description:"Cloud phone detection can be performed using the same methods as mobile emulator detection (A010-001). Additionally, device fingerprinting, abnormal environment monitoring, and outbound IP can also be used for cloud phone detection. Since cloud phones typically cannot modify the ROM and most cannot even obtain root access, the countermeasure effectiveness is generally better than mobile emulator detection (A010-001).",limitation:"As cloud phones and cloud gaming continue to develop and become more widespread, APP vendors will not be able to adopt a blanket 'cloud equals blacklisted' policy, otherwise they will face a large number of user complaints. This leaves room for the black-gray industry to exploit cloud phones in the future.",references:[{title:"NIST Guidelines for Managing the Security of Mobile Devices"}],keywords:["Cloud Phone Detection","cloud phone check","virtual phone detection","cloud handset detection","phone farm detection"]},"A0010-003":{title:"ROOT/Jailbreak Detection",definition:"Identifying whether an APP is running on a device that has been rooted or jailbroken.",description:"Detection is based on characteristics of rooted or jailbroken devices, such as: checking whether the published system version is test-keys (test build) or release-keys (release build); checking for the existence of Superuser.apk; detecting whether 'su' exists in common directories; using the 'which' command to check for 'su'; executing 'su' to see if root access can be obtained; checking for busybox; accessing the /data directory to check read/write permissions, etc.",limitation:"There are two strategies for anti-detection on rooted devices: one is to target the app and interfere with its root detection behavior; the other is to target the system and hide the system's own root-related characteristics. By reversing every root detection policy and rule in the app, anti-detection strategies can be pre-built. For example, the open-source RootCloak can hook API calls to counter root detection.",references:[{title:"Summary of Android Root Detection Methods"}],keywords:["ROOT/Jailbreak Detection","root detection","jailbreak detection","rooted device detection","jailbroken device detection","anti-rooting"]},"A0010-004":{title:"Cheat/Plugin Detection",definition:"Identifying whether a program has had runtime instructions injected or cheat programs attached.",description:"Detection is performed by checking program runtime integrity, keyword or DLL list detection, process lists, window title keywords, etc. to determine whether cheat programs are present.",limitation:"Similar to the limitations of mobile ROOT/jailbreak detection (A010-003), by analyzing and reversing the detection process, blocking or providing hooked false values can bypass cheat detection. However, since cheats are typically used in games, and game data packets are much less readable than HTTP-based APP traffic, hiding cheat detection logic and data reporting within normal game operation and communication will increase the difficulty of anti-cheat countermeasures.",references:[{title:"In-Depth Analysis of DMA Hardware Cheat Principles and Detection Techniques"}],keywords:["Cheat/Plugin Detection","anti-cheat","cheat detection","plugin detection","mod menu detection","game hack detection","DLL injection detection"]},"A0010-005":{title:"Multi-Instance Detection",definition:"Identifying whether an APP is running in multiple instances on a terminal.",description:"Game multi-instance detection simply limits the number of game processes and is divided into pre-detection, in-process detection, and post-detection. In-process and post-detection are often silent and serve as the basis for banning or penalizing accounts. Pre-detection prevents multi-instance launching and includes methods such as: process enumeration multi-instance detection, mutex object multi-instance detection, semaphore multi-instance detection, window multi-instance detection, shared memory multi-instance detection, etc.",limitation:"By analyzing and reversing the detection process, blocking or providing hooked false values can bypass multi-instance detection.",references:[{title:"MASTG-KNOW-0031: Emulator Detection - OWASP",link:"https://mas.owasp.org/MASTG-KNOW-0031/"}],keywords:["Multi-Instance Detection","multi-instance check","multi-open detection","instance limiting","multi-login detection","parallel instance detection"]},"A0010-006":{title:"Debugger Detection",definition:"Identifying whether a program is being debugged.",description:"The most basic debugger detection technique is to check the BeingDebugged flag in the Process Environment Block (PEB). Another PEB member called NtGlobalFlag (offset 0x68) is also used by packers to detect whether the program was loaded with a debugger. Kernel32!CheckRemoteDebuggerPresent() is another API that can be used to determine whether a debugger is attached to a process. When stepping over INT3 and INT1 instructions in a debugger, since the debugger typically handles these debug interrupts, the exception handler will not be called by default. Debugger Interrupts exploits this fact — a packer can set a flag in the exception handler, and if the flag is not set after the INT instruction, it means the process is being debugged. See references for more methods.",limitation:"By analyzing and reversing the detection process, blocking or providing hooked false values can bypass debugger detection.",references:[{title:"MASTG-KNOW-0085: Anti-Debugging Detection - OWASP",link:"https://mas.owasp.org/MASTG-KNOW-0085/"}],keywords:["Debugger Detection","anti-debugging","debugger check","debug detection","process debugging detection","runtime debugger detection"]},"A0010-007":{title:"Virtual Machine Detection",definition:"Identifying whether an APP is running inside a virtual machine.",description:"Virtual machine environment detection refers to software's ability to determine whether it is currently running in a virtual machine and to take corresponding action based on the result. From a malware perspective, it can change its behavior inside a virtual machine to increase analysis difficulty. From a software security perspective, it is used to prevent reverse engineering and abnormal use in certain scenarios.",limitation:"Virtual machine detection methods mainly work by checking certain environment properties and files, but these methods are not absolutely reliable because black-gray industry actors can modify the virtual machine's environment properties and files to evade detection.",references:[{title:"Virtual Machine Runtime Environment Detection"}],keywords:["Virtual Machine Detection","VM detection","virtual machine check","sandbox detection","hypervisor detection","virtualized environment detection"]},"A0010-008":{title:"Headless Browser Detection",definition:"Identifying whether an APP is running inside a headless browser.",description:"Headless browser detection refers to software's ability to determine whether it is currently running in a headless browser and to take corresponding action based on the result. From a malware perspective, it can change its behavior inside a headless browser to increase analysis difficulty. From a software security perspective, it is used to prevent reverse engineering and abnormal use in certain scenarios.",limitation:"Headless browser detection methods mainly work by checking certain environment properties and files, but these methods are not absolutely reliable because black-gray industry actors can modify the headless browser's environment properties and files to evade detection.",references:[{title:"National Cybersecurity Awareness Week: Domain Name Theft Should Not Be Underestimated"}],keywords:["Headless Browser Detection","headless Chrome detection","headless mode detection","browser automation detection","bot browser detection","Puppeteer detection"]},"A0010-009":{title:"HOOK Detection",definition:"Identifying whether an APP is running in a HOOKed environment.",description:"HOOK detection refers to software's ability to determine whether it is currently running in a HOOKed environment and to take corresponding action based on the result. From a malware perspective, it can change its behavior in a HOOKed environment to increase analysis difficulty. From a software security perspective, it is used to prevent reverse engineering and abnormal use in certain scenarios.",limitation:"HOOK detection methods mainly work by checking certain environment properties and files, but these methods are not absolutely reliable because black-gray industry actors can modify the HOOKed environment's properties and files to evade detection.",references:[{title:"Android Hook, Detection, and Countermeasures"}],keywords:["HOOK Detection","anti-hooking","API hooking detection","runtime hooking detection","function hooking","inline hooking"]}},M=e({A0011:()=>z,default:()=>O}),z={title:"Force Session Logout",definition:"Logging the user out of their session and invalidating the current login state on the server side.",description:"Forcing a session logout is a lightweight user penalty strategy (A020). Some cases are for the user's account security, such as detection and handling of cookie reuse and logins from unusual locations. Other cases aim to force the session holder to go through the identity authentication (A018) login challenge again — for example, many crawlers use session tokens for data scraping. Since the login challenge typically includes credential verification, human verification (A001), and multi-factor authentication (A007) challenges, this can effectively disrupt automated crawlers.",limitation:"Many applications support multi-point login, meaning that even after a session is forced out, the user can still access via another active session. Additionally, because forcing a session logout effectively disrupts the black-market cookie trading workflow, many black-market account vendors now provide one-click login tools that can re-login instantly even after a forced logout.",references:[{title:"Session Management - Wikipedia"}],keywords:["Force Session Logout","session logout","forced logout","session invalidation","sign out everywhere","token revocation"]},O={A0011:z},R=e({A0012:()=>H,default:()=>F}),H={title:"Forced Password Reset",definition:"Issuing a mandatory password reset to the user; the user must successfully reset their password before they can log in.",description:"Forced password resets are generally applied in scenarios such as successful credential stuffing, password leaks, logins from unusual locations, long periods of inactivity, password expiration, and unchanged default passwords. The main purpose is to use the password reset process and the identity authentication (A018) within it to verify account ownership and reduce the risk of credential exposure.",limitation:"Forced password resets have a significant negative impact on user experience.",references:[{title:"Password Policy - Wikipedia"}],keywords:["Forced Password Reset","password reset enforcement","mandatory password change","forced reset","account recovery reset","password rotation"]},F={A0012:H},W=e({A0013:()=>E,default:()=>L}),E={title:"Client Application Hardening",definition:"Applying code-level obfuscation, anti-debugging, and other protections to front-end JS scripts or client APPs.",description:"Client-side code obfuscation can, to some extent, prevent black-gray industry actors from directly reverse-engineering client-side code to analyze resource access logic and implement business automation and data scraping. It also increases the difficulty of breaking client-side human verification challenges, abnormal environment detection (A010), API signatures (A002), and other business security measures. However, because the obfuscated code still resides on the user's client, it is theoretically possible to fully reverse the obfuscated code given sufficient time and effort. Therefore, client-side code obfuscation is only a means of reducing the ROI of black-gray industry actors. However, according to the PDR formula Pt > Dt + Rt, if defenders can reduce the obfuscation cycle to within the cracking cycle, long-term protection may be achievable. Anti-debugging can be either a blocking mechanism against debugging or an interference mechanism — for example, one program logic can run in a non-debug environment and a different logic in a debug environment.",limitation:"Hardened applications can still be decompiled: although hardening increases the difficulty of decompilation, it cannot completely prevent it. Hackers can use various means to crack hardened applications and obtain source code and sensitive information. Hardened applications may have compatibility issues: since hardening modifies the application's code and structure, it may cause compatibility problems — for example, the hardened application may not run on certain devices or may crash. Hardened applications may have performance issues: since hardening increases the application's size and runtime overhead, it may cause performance problems such as slower startup or higher memory usage.",references:[{title:"Code Obfuscation - Wikipedia"}],keywords:["Client Application Hardening","app hardening","client-side hardening","code obfuscation","anti-reverse engineering","anti-tampering","anti-debugging"]},L={A0013:E,"A0013-001":{title:"Android Application Hardening",definition:"Hardening Android applications through anti-reverse engineering, anti-tampering, anti-debugging, and anti-malware measures.",description:"Multiple DEX protection modes combined with VMP virtual machines encrypt and protect critical code and core logic, preventing source code extraction via reverse engineering tools such as IDA, JEB, JADX, APKTool, and Readelf. Each file in the app is assigned a unique fingerprint; combined with signature and file integrity verification, replacing any file will prevent the app from running, guarding against ad virus injection, repackaging, and feature blocking. Multi-layer encryption combined with low-level countermeasures prevents code injection and Java/C-layer dynamic debugging, effectively resisting dynamic debugging, memory dumping, code injection, and HOOK attacks. Effectively detects and counters: ROOT, emulators, UI hijacking, multi-instance tools, Xposed plugins, Frida, and other HOOK tools. (Excerpted from dun.163.com)",limitation:"May have compatibility and runtime performance issues.",references:[{title:"OWASP Mobile Application Security"}],keywords:["Android Application Hardening","Android app hardening","APK hardening","mobile app hardening","Android anti-reverse engineering","Android code obfuscation"]},"A0013-002":{title:"iOS Application Hardening",definition:"Hardening iOS applications through anti-reverse engineering, anti-tampering, anti-debugging, and anti-malware measures.",description:"Encrypts strings to prevent keyword-based location of core business code via tools like IDA. Applies multiple obfuscation methods to application code to increase complexity and reverse analysis difficulty without affecting original logic and performance. Obfuscates application symbols to increase code reverse difficulty. Advanced anti-debugging techniques prevent attackers and malicious analysts from dynamically debugging the program. Protects binary code from being decompiled into pseudo-code by reverse analysis tools. Protects numerical values in the application from being tampered with by memory editors (e.g., attack power, HP in games). Applies integrity protection to prevent tampering, repackaging, and other cheating behaviors. (Excerpted from dun.163.com)",limitation:"May have compatibility and runtime performance issues.",references:[{title:"OWASP Mobile Application Security"}],keywords:["iOS Application Hardening","iOS app hardening","IPA hardening","mobile app hardening","iOS anti-reverse engineering","iOS code obfuscation"]},"A0013-003":{title:"H5/Mini-Program Hardening",definition:"Hardening H5 applications through anti-reverse engineering, anti-tampering, anti-debugging, and anti-malware measures.",description:"Uses encryption technology to counter dynamic debugging and prevent code from being debugged and cracked or data from being extracted. Supports strong binding of H5 applications to specified domains, preventing domain tampering that could redirect users or enable fraud. Encrypts code and script files, including dynamic encryption/decryption of strings, function names, and expressions, and obfuscates variables to increase cracking difficulty. Also supports code file compression to reduce application size. Uses encryption technology to protect data and prevent sensitive data from being obtained through network packet capture. (Excerpted from dun.163.com)",limitation:"May have compatibility and runtime performance issues.",references:[{title:"OWASP Bytecode Obfuscation"}],keywords:["H5/Mini-Program Hardening","H5 hardening","mini-program hardening","mini app hardening","webview hardening","JavaScript obfuscation","WeChat mini program security"]},"A0013-004":{title:"Desktop Application Hardening",definition:"Hardening desktop applications through anti-reverse engineering, anti-tampering, anti-debugging, and anti-malware measures.",description:"Encrypts and protects the application to prevent decompilation. Applies obfuscation to increase code complexity and reverse analysis difficulty without affecting original logic and performance. Obfuscates application symbols to increase code reverse difficulty. Advanced anti-debugging techniques prevent attackers and malicious analysts from dynamically debugging the program. Protects binary code from being decompiled into pseudo-code by reverse analysis tools. Protects numerical values in the application from being tampered with by memory editors (e.g., attack power, HP in games). Applies integrity protection to prevent tampering, repackaging, and other cheating behaviors.",limitation:"May have compatibility and runtime performance issues.",references:[{title:"OWASP Bytecode Obfuscation"}],keywords:["Desktop Application Hardening","desktop app hardening","Windows app hardening","reverse engineering protection","code obfuscation","desktop anti-tampering"]}},B=e({A0014:()=>N,default:()=>G}),N={title:"Anti-Tampering Mechanism",definition:"A set of technologies and measures designed to ensure the integrity of data, software, or information. Such mechanisms aim to prevent unauthorized modification, tampering, or damage, ensuring data trustworthiness and accuracy.",description:"Common anti-tampering methods and practices include: Digital signatures — using asymmetric encryption algorithms to generate digital signatures for data; verifying the signature confirms data integrity and source authenticity. Hash algorithms — hashing data to generate a fixed-length hash value; even a minor change in the data causes a significant change in the hash, used to verify data integrity. Access control — restricting access permissions to data and systems to prevent unauthorized modification. Secure transport protocols — using secure transport protocols (such as HTTPS) to ensure data integrity during transmission. Logging — recording key operations and events to track and verify the modification history of data.",limitation:"Key management: if key management is improper, mechanisms such as digital signatures may be attacked, affecting data integrity verification. Dependence on a trusted environment: the effectiveness of anti-tampering mechanisms depends on the overall security of the system or environment; if the overall environment is untrusted, the mechanism may be compromised. Performance impact: some anti-tampering measures may have a certain impact on system performance, especially in large-scale data processing scenarios. Human factors: human error, negligence, or insider threats may bypass anti-tampering mechanisms and affect data integrity.",references:[{title:"Tamper Protection - Wikipedia"}],keywords:["Anti-Tampering Mechanism","tamper protection","integrity protection","anti-modification","data integrity check","file integrity monitoring"]},G={A0014:N,"A0014-001":{title:"Client-Side Anti-Tampering",definition:"Ensuring the integrity of client-side programs and preventing malicious tampering.",description:"Signing and integrity-checking the client application and its associated files ensures that the program cannot run normally if content injection, repackaging, or feature blocking occurs at runtime.",limitation:"Attackers can use decompilation tools to analyze the program and find the implementation of the anti-tampering algorithm. Additionally, attackers can use debugging tools to trace the program's execution and find vulnerabilities in the anti-tampering algorithm.",references:[{title:"Code Obfuscation - Wikipedia"}],keywords:["Client-Side Anti-Tampering","client-side tamper protection","app tamper protection","anti-repackaging","anti-injection","client integrity check"]},"A0014-002":{title:"Server-Side Anti-Tampering",definition:"A set of security measures designed to protect server systems from unauthorized access, modification, or damage, ensuring the integrity of software, configurations, and data on the server.",description:"Common server-side anti-tampering measures include: Integrity checks — using hash algorithms to regularly check the integrity of critical files and system images on the server to detect tampering. Real-time monitoring — deploying real-time monitoring systems to watch server activity and file system changes, detecting anomalies promptly. Secure configuration — applying security configurations to the server OS and related services, disabling unnecessary services and ports, and following the principle of least privilege. Firewalls and Intrusion Detection Systems (IDS) — deploying firewalls and IDS to monitor and block malicious traffic and reduce unauthorized access. Regular vulnerability scanning and patch management — regularly scanning the server for vulnerabilities and applying patches promptly to prevent attackers from exploiting known vulnerabilities. Access control — using strong password policies, multi-factor authentication, and other measures to restrict server access, ensuring only authorized users can access it. Encrypted communication — using encrypted communication protocols (such as SSH, HTTPS) to protect communication between the server and clients.",limitation:"Zero-day vulnerabilities: anti-tampering mechanisms may not defend against undisclosed zero-day vulnerabilities since no corresponding fix exists yet. False positives and false negatives: security tools may produce false positives or false negatives, leading to misinterpretation of normal operations or overlooking real threats. Human factors: administrator misconfiguration, negligence, or insider threats may bypass anti-tampering measures. Performance impact: strong anti-tampering measures may sometimes have a certain impact on server performance.",references:[{title:"File Integrity Monitoring - Wikipedia"}],keywords:["Server-Side Anti-Tampering","server-side tamper protection","server integrity checks","file integrity monitoring","configuration integrity","change detection"]}},U=e({A0015:()=>_,default:()=>j}),_={title:"Risk Control Strategy",definition:"Implementing existing or additional risk control strategies to mark and manage special users or behaviors.",description:"Risk control is the most widely applied measure in business security and is an essential tool for defending against major business operational risks. The security capability level of risk control is heavily dependent on its strategies — this is both an advantage and a disadvantage. The advantage is flexibility in business protection; the disadvantage is coverage of business protection scenarios. Additionally, because risk control can have many risk handling stages and post-processing logic, it can avoid direct confrontation with attackers at high-adversarial stages, achieving long-term effectiveness. However, precisely because of this, compared to some other security measures, risk control can be lagging in certain situations — for example, some identification and handling occurs after the business process has completed, which may cause some financial loss and may also lead to a poor user experience.",limitation:"Risk control strategies may be affected by data quality, data sources, and data processing, leading to inaccurate risk assessments. Additionally, risk control strategies may be limited by technical means — for example, some fraud methods may not be detectable by traditional risk control technology.",references:[{title:"50+ Experts Discuss LLM Technology Evolution: 2024 Global Machine Learning Technology Conference"}],keywords:["Risk Control Strategy","risk control","fraud prevention","risk management strategy","policy controls","rule engine","risk rules"]},j={A0015:_},K=e({A0016:()=>V,default:()=>J}),V={title:"Threat Intelligence",definition:"Marking black-market identities using threat intelligence such as blacklisted IP databases and blacklisted phone number databases.",description:"Also commonly abbreviated as TI or CTI. The definition of threat intelligence can be very broad: any data label that can identify good or bad is threat intelligence. Threat intelligence places high demands on intelligence operations capability and intelligence quality, requiring data to remain fresh on a continuous and real-time basis. Precision and recall are generally used as metrics for threat intelligence quality. Good threat intelligence can be used directly as a protective measure, while poor-quality threat intelligence needs to be combined with risk control strategies (A015) to avoid incomplete coverage or large-scale false positives.",limitation:"The limitations of threat intelligence mainly include: incomplete information sources, timeliness challenges, excessive false information, difficulty distinguishing targeted attacks, difficulty quantifying real impact, challenges in cross-organizational sharing and collaboration, and compliance issues related to privacy and regulations.",references:[{title:"Guide to Cyber Threat Information Sharing - NIST SP 800-150",link:"https://nvlpubs.nist.gov/nistpubs/specialpublications/nist.sp.800-150.pdf"},{title:"NIST SP 800-150: Guide to Cyber Threat Information Sharing"}],keywords:["Threat Intelligence","CTI","cyber threat intelligence","threat feeds","intel sharing","indicator feeds","threat intel"]},J={A0016:V,"A0016-001":{title:"IP Intelligence",definition:"Labeling IP addresses with risk scores, types, and other attributes.",description:"IP intelligence refers to various information about IP addresses. In a narrow sense, IP intelligence may only include the risk score of an IP. In a broad sense, IP intelligence also includes: geographic location, ISP (Internet Service Provider) information, ASN (Autonomous System Number), malicious activity history, user information, proxy detection, network traffic analysis, etc.",limitation:"The limitations of IP threat intelligence are that it can only provide limited information and cannot provide a complete threat picture. Additionally, since network attackers constantly change their attack methods and techniques, the effectiveness of IP intelligence can also be affected. Therefore, when using IP intelligence, it needs to be combined with other security technologies and measures to improve the effectiveness of network security protection.",references:[{title:"Threat Intelligence - Wikipedia"}],keywords:["IP Intelligence","IP reputation","IP risk scoring","proxy detection","geolocation intelligence","IP reputation data"]},"A0016-002":{title:"Domain & Link Threat Intelligence",definition:"Labeling malicious domains or links.",description:"Compared to IP intelligence (A016-001), domain and link intelligence has higher accuracy and effectiveness, but its use cases are more limited: IP intelligence can be applied to virtually any network request scenario, while domain and link intelligence is typically only applicable to malicious link detection (A006-005) scenarios.",limitation:"Domain-level threat intelligence has the problem of being too broad, making domain-based blocking prone to false positives. Link-level intelligence has the problem of being too narrow, meaning that simply modifying a link descriptor can bypass detection.",references:[{title:"Information Sharing - CISA",link:"https://www.cisa.gov/topics/cyber-threats-and-advisories/information-sharing"}],keywords:["Domain & Link Threat Intelligence","domain intelligence","URL intelligence","malicious domain detection","link reputation","phishing domain reputation"]},"A0016-003":{title:"Phone Number Intelligence",definition:"Labeling black-market phone numbers, recycled numbers, etc.",description:"Black-market phone numbers are mostly generated from risk control systems and risk device identification countermeasures. Recycled numbers (numbers reassigned to new users) typically come from carriers; by connecting to carrier interfaces, businesses can promptly obtain the active status and secondary identity binding status of phone numbers.",limitation:"Black-market actors can obtain phone numbers by renting real people's phone numbers. Additionally, interception SIM cards (real phones with malware installed to intercept SMS messages) have a high market share in the black-market industry and have become the most mainstream type of malicious phone number. Although these phone numbers are used for black-gray market activities, they cannot be directly blocked as blacklisted numbers.",references:[{title:"Thousands of Phones Hacked by Spyware - Xinhua"}],keywords:["Phone Number Intelligence","phone reputation","phone number risk","recycled number detection","virtual number detection","blacklisted number"]},"A0016-004":{title:"IOC (Indicator of Compromise) Intelligence",definition:"IOC (Indicator of Compromise) intelligence refers to specific markers and characteristics used to detect and confirm whether a computer system or network has been threatened or compromised. These markers can include specific file hashes, IP addresses, domain names, malicious file behavior patterns, etc.",description:"Content may include: file hash values — unique identifiers of malicious files, used to identify known malware. IP addresses — known malicious IP addresses associated with malicious activity. Domain names — potentially malicious domain names associated with threats. Malicious file behavior patterns — specific malware may have unique behavior patterns that can serve as threat indicators.",limitation:"The limitations of IOC intelligence include dependence on known attack patterns, vulnerability to attackers changing IOCs, susceptibility to false positives and false negatives, and its static-feature-based nature making it difficult to adapt to dynamic and evolving threat environments.",references:[{title:"OASIS Cyber Threat Intelligence Technical Committee",link:"https://oasis-open.github.io/cti-documentation/"}],keywords:["IOC (Indicator of Compromise) Intelligence","IOC intelligence","IOCs","indicators of compromise","threat indicators","malware indicators"]},"A0016-005":{title:"Risk Address Intelligence",definition:"Labeling false or malicious shipping and contact addresses entered by users.",description:"Such intelligence systems typically combine data analysis, machine learning, and AI technologies to extract patterns, behaviors, and characteristics from large data sources to identify potentially risky addresses. Key aspects include: fake identity and fraud detection — analyzing user-provided address information against other data points (such as name, contact information) to identify fake identities or fraudulent behavior. Historical behavior analysis — analyzing past user behavior patterns to identify abnormal or unusual address entry behavior, such as frequently changing addresses or using similar fake addresses. Geographic information verification — using GIS and geolocation data to verify whether user-provided addresses match actual geographic locations. Social network analysis — linking user address information with their social network activity and relationships to help detect potential fraud or illegal activity. Blacklist matching — matching against known blacklists of addresses associated with fraud and malicious activity.",limitation:"Limitations include the possibility of false information evading detection, high false positive rates, strong dependence on data quality, privacy concerns, constraints from geographic diversity, insufficient adaptability to new fraud forms, potential negative impact on user experience, and relatively high implementation and maintenance costs.",references:[{title:"Guide to Cyber Threat Information Sharing - NIST SP 800-150",link:"https://nvlpubs.nist.gov/nistpubs/specialpublications/nist.sp.800-150.pdf"}],keywords:["Risk Address Intelligence","address risk scoring","shipping address fraud","address reputation","fraud address screening","delivery address intelligence"]}},Q=e({A0017:()=>X,default:()=>Z}),X={title:"Additional Identity Authorization",definition:"Adding permission verification to the application workflow to re-confirm the user's request intent and true identity.",description:"Additional identity authorization can be applied in business scenarios such as: payment, password changes, identity binding, third-party OAuth authorization, coupon redemption, points redemption, account cancellation, etc. Available forms include: entering a password, facial recognition, fingerprint recognition, phone verification code, etc.",limitation:"Adding identity authorization via password entry is only suitable for scenarios where the goal is to have the user re-confirm their request intent, or to defend against stolen login credentials (e.g., cookies). Since it cannot guarantee that the person who knows the login password is the actual account owner, it is not very effective for confirming the user's true identity. In many cases, users are required to set a separate password in addition to the login password, such as a payment password.",references:[{title:"Multi-Factor Authentication - Wikipedia"}],keywords:["Additional Identity Authorization","step-up authorization","secondary authorization","reauthentication","transaction approval","consent confirmation"]},Z={A0017:X,"A0017-001":{title:"Access Control System",definition:"A system that controls the access permissions of personnel by verifying their identity, thereby achieving the goal of security management.",description:"Access control systems come in many types and forms. Common types include: password-based access control — identity verification through entering a specific numeric password, usually combined with a mechanical lock. Card-based access control — identity recognition using magnetic cards, IC cards, RFID cards, etc., common in office buildings and residential communities. Biometric access control — using biometric technologies such as fingerprint recognition, facial recognition, and iris recognition, offering high security. Mobile app access control — remote door opening via a smartphone app, suitable for smart homes and self-service libraries. Combined access control — combining multiple identity recognition methods, such as fingerprint + password or card + biometrics, to improve security. Cloud-based access control — remote management and monitoring via cloud computing, common in large enterprises or public venues. Special access control — such as inductive loop access control and infrared sensing access control, suitable for specific environments and special needs. Each type has its own advantages and disadvantages and is suitable for different application scenarios. Choosing the right type requires considering security requirements, ease of use, and cost.",limitation:"Non-biometric access control systems are susceptible to credential theft. Additionally, access control systems that do not implement precise flow control can be bypassed by tailgating.",references:[{title:"Access Control Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Access_Control_Cheat_Sheet.html"}],keywords:["Access Control System","access control","authorization system","permission management","ACL","policy enforcement"]}},Y=e({A0018:()=>$,default:()=>ee}),$={title:"Identity Authentication (Login)",definition:"Requiring users to confirm their identity through login or similar means when requesting related resources from a terminal.",description:"In most cases, identity authentication takes the form of login. Without verifying login status, it is very difficult to continuously monitor terminal access behavior, because both request characteristics and request sources are trivially easy to forge. This makes evading server-side continuous monitoring of terminal access a common method for avoiding penalties for resource abuse. For this reason, many businesses now use identity authentication as an effective means of achieving continuous monitoring of terminal access behavior. Without authentication, terminals can only access a limited type or quantity of resources; to access more resources, identity authentication is required.",limitation:"The protective effectiveness of identity authentication is heavily dependent on the cost of obtaining a business identity — both the registration cost and the login authentication cost — and is also closely related to the severity of account penalties (A020). Some websites allow arbitrary bulk registration of user identities, in which case the value of identity authentication is very limited.",references:[{title:"Authentication - Wikipedia"}],keywords:["Identity Authentication (Login)","login","sign in","authentication","user authentication","account login"]},ee={A0018:$,"A0018-001":{title:"Zero-Knowledge Proof",definition:"A special interactive protocol that allows a prover to prove to a verifier that a statement is true without providing any information about the statement to the verifier.",description:"The basic idea of zero-knowledge proof is that the prover, through a series of interactions, proves to the verifier that they know the evidence for a statement, but in this process the prover does not reveal any information about the evidence. A typical application scenario is identity authentication: the prover can prove to the verifier that they know a certain password without revealing any information about the password. For example, in an e-commerce scenario, when a user's identity is in doubt, the user can confirm their identity by selecting products they have previously purchased. Or in a social scenario, the user can confirm their identity by selecting their own friends.",limitation:"Users may lose access to certain knowledge, making it impossible to pass verification.",references:[{title:"Verifiable Credentials Data Model - W3C",link:"https://www.w3.org/TR/vc-data-model-2.0/"}],keywords:["Zero-Knowledge Proof","ZKP","zero knowledge proof","zero-knowledge protocol","proof of knowledge","privacy-preserving proof"]}},ie=e({A0019:()=>te,default:()=>ne}),te={title:"Identity Security Audit",definition:"Conducting continuous security audits of user accounts to detect account risks in a timely manner.",description:"Similar to the risk monitoring mechanism of risk control strategies (A015), identity behavior monitoring and risk assessment is also an audit-based protective measure. However, the two differ in their protection subjects and objects: risk control protects the business from users, while identity behavior auditing protects users from attackers. Identity security auditing is a commonly used means of assessing identity security. After an anomaly is detected, it needs to be combined with other identity measures such as re-authentication (A018), multi-factor authentication (A007), and forced password reset (A012).",limitation:"Generally, identity security auditing relies on detecting abnormal account behavior, which requires a certain amount of time and data as a reference baseline. Additionally, in some cases, identity security auditing has a certain degree of latency — subsequent handling or loss mitigation is required after a risk is identified.",references:[{title:"Security Audit - Wikipedia"}],keywords:["Identity Security Audit","account audit","identity audit","user account audit","security review","account risk review"]},ne={A0019:te,"A0019-002":{title:"Invitation Code Mechanism",definition:"A mechanism that restricts user registration through invitation codes.",description:"When registering, users must enter an invitation code to complete registration. Invitation codes can be generated by administrators or by other users. The invitation code mechanism can effectively prevent malicious registration, but requires administrators or other users to generate invitation codes, so the cost is relatively high.",limitation:"The invitation code mechanism increases the cost of user registration and is therefore not suitable for scenarios with a large volume of user registrations.",references:[{title:"A Brief History of Google"}],keywords:["Invitation Code Mechanism","invite code system","referral code","invitation-only signup","beta invite","registration gate"]},"A0019-003":{title:"Friend-Assisted Authentication",definition:"A mechanism that uses the user's friends to assist in authenticating the user's identity.",description:"When registering or authenticating, users must select their friends, and the system sends verification information to those friends. The user must pass verification by those friends to complete registration.",limitation:"If the user has no friends, or if friends are unwilling to help with verification, the user will be unable to complete registration.",references:[{title:"WeChat Friend-Assisted Verification"}],keywords:["Friend-Assisted Authentication","social verification","friend verification","contact verification","peer-assisted authentication","friend-assisted login"]}},ae=e({A0020:()=>oe,default:()=>se}),oe={title:"Account Penalty",definition:"Penalizing accounts when they violate related rules, and prohibiting related behaviors or actions.",description:"Identity penalty strategies are an effective means of limiting the continuous damage caused by illegal or non-compliant users to the business. Identity penalties can operate at two levels: one is restrictions on the account itself, such as temporary suspension, public warning, or revocation of authorization; the other is restrictions on the resources accessible to the account, such as disabling specific business functions, limiting resource usage frequency, deleting resources, or restricting access to illegal resources.",limitation:"Account penalties are a loss-mitigation strategy with a certain degree of latency.",references:[{title:"OWASP Blocking Brute Force Attacks"}],keywords:["Account Penalty","account sanctions","account suspension","account restriction","disciplinary action","enforcement action"]},se={A0020:oe,"A0020-001":{title:"Store Penalty",definition:"Penalizing a store when it violates related rules, and prohibiting related behaviors or actions.",description:"Store penalty strategies include: lowering credit ratings, lowering tier levels, taking down products, reducing search ranking weight, suspending the store, banning the store, fines, etc.",limitation:"Store penalties are a loss-mitigation strategy with a certain degree of latency.",references:[{title:"Interpretation of the Personal Fine System"}],keywords:["Store Penalty","merchant penalty","store suspension","shop sanctions","seller penalty","merchant sanctions"]},"A0020-002":{title:"Employee Penalty",definition:"Employee penalty strategies are a set of sanctions established by an organization in response to employees violating company rules or policies.",description:"Penalty content may include verbal warnings, written warnings, suspension, demotion, salary deductions, termination, etc. Effective employee penalty strategies should balance punishment and improvement, making employees aware of the consequences of misconduct while providing opportunities for correction and improvement.",limitation:"Limitations include the potential to cause employee dissatisfaction and affect the work environment. Compliance must be ensured to guard against legal action. Therefore, fair, clear, and consistently enforced strategies must be developed in alignment with relevant regulations and company policies.",references:[{title:"Ministry of Public Security Releases Top 10 Financial Black-Grey Market Crime Cases"}],keywords:["Employee Penalty","employee sanctions","disciplinary action","workplace discipline","staff penalty","HR sanctions"]},"A0020-003":{title:"Account Ban",definition:"Banning an account when it violates related rules, preventing the account from logging in.",description:"Account ban strategies include: account ban, account freeze, account deactivation, account deletion, etc.",limitation:"Account banning is a loss-mitigation strategy with a certain degree of latency.",references:[{title:"Account Lockout - NIST SP 800-53"}],keywords:["Account Ban","account lockout","account freeze","account suspension","deactivation","ban"]}},re=e({A0021:()=>ce,default:()=>le}),ce={title:"Device Fingerprinting",definition:"Device characteristics or unique device identifiers that can be used to uniquely identify a device.",description:"Device fingerprinting is a method used to identify and label computing devices (such as smartphones, tablets, computers, etc.). It uses the hardware and software characteristics of the device itself to create a unique identifier for recognizing and verifying the device in future accesses. Device fingerprints include some inherent, difficult-to-tamper, and unique device identifiers — for example, the IMEI number assigned to each phone during manufacturing, or the MAC address assigned to a computer's network card. These unique device identifiers can be considered device fingerprints. Additionally, a combination of device characteristics such as name, model, shape, color, and features can also be used as a device fingerprint.",limitation:"For unique identifiers in devices such as IMEI, IMSI, MAC address, Android ID, and IDFA, due to user privacy restrictions and system upgrades, these generally require user authorization to access. This makes universality a problem, especially since black-gray market devices will basically never grant such permissions. For device identifiers computed from multiple device characteristics, they are too easily tampered with, making recall impossible.",references:[{title:"Fingerprinting - MDN Web Docs",link:"https://developer.mozilla.org/en-US/docs/Glossary/Fingerprinting"},{title:"OWASP Web Security Testing Guide - Fingerprint Web Server"}],keywords:["Device Fingerprinting","device fingerprint","browser fingerprinting","browser fingerprint","terminal fingerprinting","device profiling"]},le={A0021:ce,"A0021-001":{title:"Device Tagging",definition:"Tagging terminals using device characteristics, persistent cookies, and other methods.",description:"Also called terminal tagging or device labeling. Device tagging can typically be implemented through covert tracking markers and special device characteristic collection. Device tagging generally serves two purposes: one is to assign a unique identifier to the device so that the device's identity is known when the tag is present; the other is to assign a special label to the device (such as 'clean device' or 'blacklisted device') so that even after the device changes its fingerprint, the device's security status can still be continuously identified and tracked.",limitation:"Due to the inability to guarantee terminal data integrity, combined with legal and regulatory requirements for user privacy, terminal tagging has significant constraints and is only effective under certain conditions.",references:[{title:"Device Fingerprint - Wikipedia"}],keywords:["Device Tagging","device labeling","terminal tagging","persistent device ID","device tracking","covert tracking"]}},de=e({A0022:()=>ue,default:()=>me}),ue={title:"Traffic Encryption",definition:"Encrypting network request traffic or response traffic.",description:"Traffic encryption typically provides a protection mechanism for process security. By encrypting data during transmission, attackers cannot directly obtain the original data or directly modify it.",limitation:"Traffic encryption increases the complexity and cost of data transmission. When using traffic encryption, the trade-off between security and performance impact needs to be considered.",references:[{title:"Transport Layer Security - Wikipedia"}],keywords:["Traffic Encryption","network encryption","in-transit encryption","transport encryption","TLS","HTTPS"]},me={A0022:ue,"A0022-001":{title:"Transport Protocol Encryption",definition:"Encrypting the entire transport layer or application layer communication data using custom algorithms or modified standard encryption algorithms.",description:"Transport layer encryption refers to encrypting data at the transport layer to ensure data is not stolen or tampered with during transmission — for example, modified SSL or TLS. Application layer encryption refers to encrypting data at the application layer — for example, modified HTTPS. Since the data transport protocol itself is encrypted, the specific business scenarios above it can be ignored, achieving full business scenario coverage below the application layer.",limitation:"Not applicable to scenarios where users access web pages via a browser.",references:[{title:"Transport Layer Security - Wikipedia"}],keywords:["Transport Protocol Encryption","transport encryption","TLS","SSL","protocol encryption","application-layer encryption"]},"A0022-002":{title:"Request Data Encryption",definition:"Encrypting request data sent to the server.",description:"Request data encryption refers to encrypting the request body on top of an existing protocol (such as HTTPS) before sending it to the server, to ensure data is not stolen or tampered with during transmission. Request data encryption can be applied in any business scenario, but requires decryption logic to be added on the server side.",limitation:"Generally implemented by hooking the remote request function to encrypt data, but this may cause certain compatibility issues. If some business logic does not use a unified remote request function, that portion of data cannot be encrypted.",references:[{title:"OWASP REST Security Cheat Sheet"}],keywords:["Request Data Encryption","request payload encryption","encrypted request body","client-side encryption","body encryption","end-to-end request encryption"]},"A0022-003":{title:"Response Data Encryption",definition:"Encrypting response data from the server.",description:"Response data encryption refers to encrypting the response body on the server side to ensure data is not stolen or tampered with during transmission. Response data encryption can be applied in any business scenario, but requires decryption logic to be added on the client side.",limitation:"Generally implemented by hooking the remote request function to encrypt data, but this may cause certain compatibility issues. If some business logic does not use a unified remote request function, that portion of data cannot be encrypted.",references:[{title:"OWASP REST Security Cheat Sheet"}],keywords:["Response Data Encryption","response payload encryption","encrypted response body","server-side encryption","body encryption","end-to-end response encryption"]},"A0022-004":{title:"Custom Transport Protocol",definition:"Using a custom transport protocol instead of standard protocols.",description:"A custom transport protocol refers to defining a custom protocol at the transport or application layer, or modifying a common protocol to make it non-standard, to ensure data cannot be parsed or tampered with during transmission. Custom transport protocols can be applied in any business scenario, but require custom protocol parsing logic to be added on both the client and server sides.",limitation:"Custom transport protocols require custom protocol parsing logic on both the client and server sides, and the protocol versions on both sides must be consistent; otherwise communication will fail.",references:[{title:"OWASP Cryptographic Storage Cheat Sheet"}],keywords:["Custom Transport Protocol","custom protocol","proprietary protocol","non-standard protocol","protocol obfuscation","custom transport"]}},he=e({A0023:()=>ge,default:()=>pe}),ge={title:"Biometric Identification",definition:"Identifying and verifying user identity by recognizing and comparing human biometric characteristics.",description:"Face, fingerprint, voiceprint, iris, gait, palm print, vein pattern, DNA, and other human biometric characteristics all have a certain degree of uniqueness. Currently, the most commonly used for remote comparison on mobile devices are face, facial features, and voiceprint. Since facial recognition and voiceprint recognition face very intense adversarial competition, they are currently mainly used as a third verification factor beyond basic identity authentication (A018) and two-factor authentication (A007), and are more focused on preventing identity impersonation than account theft.",limitation:"High false recognition rate: biometric identification technology in practical applications can have a high false recognition rate due to environmental, device, and physiological change factors. Susceptibility to attack: biometric identification technology has certain security risks — biometric characteristics such as face, voiceprint, fingerprint, and iris can be copied or forged, leading to system attacks. Privacy leakage: biometric identification technology requires collecting users' biometric information; if this information is leaked, it will pose a threat to user privacy.",references:[{title:"Biometric Technology - Wikipedia"}],keywords:["biometrics","biometric authentication","biometric verification"]},pe={A0023:ge,"A0023-001":{title:"Facial Recognition",definition:"Identifying and verifying user identity by recognizing and comparing facial features.",description:"Facial recognition is a biometric identification technology that identifies and verifies user identity by recognizing and comparing facial features. The main steps include face detection, facial feature extraction, and facial feature comparison. Applications on mobile devices include face unlock, face payment, and face check-in.",limitation:"Facial recognition technology has certain security risks — facial images can be copied or forged, leading to system attacks.",references:[{title:"Facial Recognition System - Wikipedia"}],keywords:["face recognition","face authentication","face unlock"]}},fe=e({A0024:()=>ye,default:()=>be}),ye={title:"Real-Name Identity Verification",definition:"Binding a virtual identity to a real-world identity.",description:"A person's or entity's real-world identity includes legally recognized documents such as national ID cards, household registration books, driver's licenses, military officer IDs, soldier IDs, passports, and business licenses. The real-name identity verification process is the process of binding a person's or entity's online virtual identity to their real-world identity. This process may use biometric identification (A023) and other methods to confirm the validity of the real-world identity.",limitation:"Because personal ID document information leaks occur frequently, it is not sufficient to verify identity ownership by simply entering an ID number or photographing an ID document. It is necessary to combine facial recognition, SMS verification linked to the registered phone number, bank card holder verification, and other methods to confirm the document owner.",references:[{title:"Digital Identity Guidelines: Enrollment and Identity Proofing - NIST SP 800-63A",link:"https://pages.nist.gov/800-63-3/sp800-63a.html"},{title:"Ministry of Public Security Announces Top 10 Black-Grey Market Crime Cases"}],keywords:["real name verification","identity proofing","KYC"]},be={A0024:ye},ve=e({A0025:()=>we,default:()=>ke}),we={title:"Digital Certificate",definition:"Digitally signing and encrypting data or files through a digital certificate mechanism.",description:"Unlike API signature verification (A002), digital certificates place more emphasis on the integrity of the entire transmission chain from sender to receiver, and can also serve as a mechanism for verifying the sender's authenticity. API signatures focus more on ensuring the integrity of data passed from the client and across sites. Simply put, digital certificates primarily protect the data transmission process, while API signatures primarily protect the user terminal.",limitation:"Since digital certificates are issued by trusted third-party authorities, the security of digital certificates is heavily dependent on the trustworthiness of the issuing authority. If the issuing authority is compromised, attackers can forge digital certificates. Additionally, the security of digital certificates is also affected by the signing algorithm — if the signing algorithm is compromised, attackers can forge digital signatures.",references:[{title:"Transport Layer Security Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Transport_Layer_Security_Cheat_Sheet.html"},{title:"RFC 5280: Internet X.509 Public Key Infrastructure Certificate and CRL Profile"}],keywords:["X.509 certificate","PKI certificate","public key certificate"]},ke={A0025:we,"A0025-001":{title:"Email Digital Certificate",definition:"Providing trustworthiness guarantees for email senders and integrity and confidentiality guarantees for email content.",description:"Digitally signing and encrypting emails and attachments provides a high level of confidentiality and security for electronic communications. Encryption means only the intended recipient can read the email, while digital signatures allow them to confirm the sender and verify that the email was not tampered with in transit. (Excerpted from Tencent Cloud)",limitation:"Using email digital certificates can be relatively complex — users need to understand the concept of digital certificates, purchase certificates, configure email clients, etc. This may create a barrier for general users. Digital certificates need to be renewed on time, and updates must be performed before expiration. Certificate management can become complex, especially for large-scale deployments. For end-to-end encryption and signing to work, both the sender and recipient must support and configure digital certificates, which may impose limitations when communicating with users who do not use digital certificates. Email digital certificates can only provide security during transmission and cannot address endpoint security issues such as password leaks or malware infections.",references:[{title:"Recommendation for Key Management - NIST SP 800-57 Part 1 Rev. 5",link:"https://csrc.nist.gov/pubs/sp/800/57/pt1/r5/final"}],keywords:["S/MIME","email signing certificate","email encryption certificate"]},"A0025-002":{title:"HTTPS Digital Certificate",definition:"Providing trustworthiness, integrity, and confidentiality guarantees for HTTP requests.",description:"By purchasing and installing an HTTPS certificate service, the trustworthiness, integrity, and confidentiality of user requests to the server are guaranteed.",limitation:"The security of HTTPS digital certificates is heavily dependent on the trustworthiness of the issuing authority. If the issuing authority is compromised, attackers can forge digital certificates. Additionally, the security of HTTPS digital certificates is also affected by the signing algorithm — if the signing algorithm is compromised, attackers can forge digital signatures.",references:[{title:"Transport Layer Security Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Transport_Layer_Security_Cheat_Sheet.html"}],keywords:["SSL certificate","TLS certificate","server certificate"]},"A0025-003":{title:"Electronic File Seal",definition:"Providing trustworthiness and integrity signing guarantees for files.",description:"Provides full-chain trusted behavior authentication for online contracting, contract management (historical contracts, contract templates), electronic data preservation and notarization, and real-time evidence collection of electronic documents (electronic contracts, electronic orders, electronic agreements, etc.). By ensuring the completeness, trustworthiness, and non-tamperability of electronic data throughout its entire lifecycle, it effectively resolves the difficulties of electronic data preservation, management, and judicial authentication. (Excerpted from jdcloud.com)",limitation:"Using electronic file seals may be relatively complex for general users, requiring understanding of digital signatures and seals and how to correctly apply and verify them. The trustworthiness and validity of electronic file seals depend on the reliability of the underlying Public Key Infrastructure (PKI). If the PKI is attacked or has issues, the trustworthiness of the electronic seal will be threatened.",references:[{title:"Recommendation for Key Management - NIST SP 800-57 Part 1 Rev. 5",link:"https://csrc.nist.gov/pubs/sp/800/57/pt1/r5/final"}],keywords:["electronic seal","e-seal","digital seal"]},"A0025-004":{title:"USB Key Digital Certificate",definition:"A USB interface hardware device with a built-in microcontroller or smart card chip, with a certain amount of storage space, capable of storing the user's private key and digital certificate.",description:"Authentication information required for client login (such as username, password, QQ, email, phone, ID number, etc.) can all be written into the USB key. Algorithms and code can also be written in, allowing the key to replace the traditional 'username + password' login method, achieving the goal of only being able to log in to a website or application system when the key is plugged in. Developers can also set the USB key to work alongside the traditional 'username + password' login mode as needed. The USB key can be used for access control, setting different clients to have different permissions — for example, some clients can only use part of the website or system's features, or different clients use different modules. It can also be configured to require the USB key to remain plugged in during use, or to automatically log out after a set time following removal.",limitation:"The device is easy to lose or be stolen, potentially leading to unauthorized access to sensitive information. Depends on the login system's support — if the system does not support USB Key login, the USB Key cannot be used.",references:[{title:"FIDO2: Moving the World Beyond Passwords",link:"https://fidoalliance.org/fido2/"}],keywords:["USB token","hardware token","smart card certificate"]}},Ae=e({A0026:()=>Se,default:()=>Pe}),Se={title:"Credential Reuse Detection",definition:"Analyzing credential usage patterns to identify whether credentials are being maliciously reused.",description:"Credential reuse detection is a commonly used method for identifying malicious accounts. It can be applied in any business scenario by analyzing data collected from terminals or request characteristics on the server side to determine whether the same access credential is being used in multiple places. Common detection methods include: User-Agent analysis, IP analysis, device fingerprint analysis, etc.",limitation:"Because normal users also experience IP drift, IP analysis is generally based on geographic region. If an attacker uses a local proxy IP and also modifies the UA and device fingerprint, detection may be bypassed. The author (Monyer) has filed a patent titled 'An Identity Impersonation Detection Technology Based on Access Bifurcation Analysis' to address this problem.",references:[{title:"Credential Stuffing Prevention Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Credential_Stuffing_Prevention_Cheat_Sheet.html"}],keywords:["credential stuffing","password reuse detection","shared credential detection"]},Pe={A0026:Se},Te=e({A0027:()=>Ie,default:()=>Ce}),Ie={title:"Customer Service Follow-Up Confirmation",definition:"Using customer service phone follow-ups and similar methods to confirm user authenticity or the legitimacy of their actions.",description:"In certain specialized business scenarios (such as financial scenarios), when the system identifies abnormal user behavior during the handling process, customer service phone follow-ups can be combined to notify users or verify user legitimacy.",limitation:"Because customer service follow-up confirmation has a relatively high cost, it is generally only used for confirming major business risks rather than all business risks. Additionally, the effectiveness of customer service follow-up confirmation is heavily dependent on the professionalism and attitude of the customer service staff.",references:[{title:"Digital Identity Guidelines: Authentication and Lifecycle Management - NIST SP 800-63B",link:"https://pages.nist.gov/800-63-3/sp800-63b.html"}],keywords:["callback verification","outbound verification call","phone verification"]},Ce={A0027:Ie},xe=e({A0028:()=>De,default:()=>qe}),De={title:"Resource Access Restriction",definition:"Restricting the resources accessible to a requester.",description:"Unlike account penalty strategies (A020), resource access restrictions do not necessarily require obtaining the user's login identity. By using session information delivered to the terminal by the browser, access IP information, or unique device IDs obtained through terminal tracking (A021), the accessor can be identified. On this basis, specific business functions can be disabled, resource usage frequency can be limited, resources can be deleted, or access to illegal resources can be restricted.",limitation:"In non-login scenarios, resource access restrictions can only rely on terminal factors such as IP, UA, and device ID, all of which can be forged. This limits the effectiveness of this measure against sophisticated attackers.",references:[{title:"Authorization Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html"}],keywords:["resource-level access control","content access restriction","access throttling"]},qe={A0028:De,"A0028-001":{title:"Restrict Off-Site Access",definition:"Restricting access from external sites by checking the Referer header and similar methods.",description:"Generally applied to image, video, and file resource requests. Restricting off-site access can reduce unnecessary server load and is also an effective way to prevent resource abuse.",limitation:"It should be noted that the Referer field can be forged, so this technique is not completely reliable. Additionally, some browsers provide a Referrer Policy option that controls whether the browser includes the Referer field in requests, making it difficult to determine the access source.",references:[{title:"Authorization Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html"}],keywords:["hotlink protection","referer check","anti-hotlinking"]}},Me=e({A0029:()=>ze,default:()=>Oe}),ze={title:"Data Profiling",definition:"Collecting and analyzing various data to form labeled profiles of that data.",description:"Data profiling refers to labeled data models abstracted from data attributes, data behaviors, and other information.",limitation:"Data quality issues: data profiling requires large amounts of data; if data quality is poor, it will affect profile accuracy. Data privacy issues: data profiling requires collecting large amounts of data; if not handled properly, it will involve data privacy concerns. Timeliness issues: data profiling is based on historical data analysis and prediction; if the data is outdated or inaccurate, it will affect the timeliness of the profile.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"},{title:"GB/T 35273-2020 Information Security Technology - Personal Information Security Specification"}],keywords:["dataset profiling","data quality analysis","attribute profiling"]},Oe={A0029:ze,"A0029-001":{title:"User Profiling",definition:"Labeling users and describing them through various tags.",description:"User profiling refers to labeled user models abstracted from user attributes, preferences, lifestyle habits, and behavior. In plain terms, it means assigning tags to users — tags are highly refined characteristic identifiers derived from analyzing user information. Through labeling, users can be described using highly summarized, easy-to-understand characteristics, making it easier for people to understand users and for computers to process them.",limitation:"Data quality issues: user profiling requires large amounts of data; if data quality is poor, it will affect profile accuracy. Data privacy issues: user profiling requires collecting large amounts of user data; if not handled properly, it will involve user privacy concerns. Timeliness issues: user profiling is based on historical data analysis and prediction; if the data is outdated or inaccurate, it will affect the timeliness of the profile.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"}],keywords:["customer profiling","audience segmentation","persona building"]},"A0029-002":{title:"IP Profiling",definition:"Analyzing the behavior and characteristics of an IP address and associating it with various labels and attributes to form a comprehensive understanding of that IP address.",description:"IP profiling can include multiple aspects such as the IP address's geographic location, carrier, network quality, and user profile, and can be used to determine whether the IP address poses a risk or is a malicious IP. In the network security field, IP profiling is an important technical means that can help enterprises better understand threats and anomalous behavior in the network, improving network security protection capabilities. Through IP profiling, enterprises can quickly locate and handle malicious attacks, fraud, and other network security incidents, protecting business and data security.",limitation:"With the proliferation of IPv6, the number of IP addresses will increase dramatically, posing greater challenges for IP profiling technology.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"}],keywords:["IP reputation","IP intelligence","IP enrichment"]},"A0029-003":{title:"Device Profiling",definition:"Labeling devices and describing them through various tags.",description:"Device profiling refers to labeled device models abstracted from device attributes and device behaviors.",limitation:"Device profiling is an extension of device fingerprinting (A0021). If device fingerprinting is inaccurate, device profiling will also be affected. Additionally, the accuracy of device profiling is also affected by the device profiling algorithm.",references:[{title:"Fingerprinting - MDN Web Docs",link:"https://developer.mozilla.org/en-US/docs/Glossary/Fingerprinting"}],keywords:["device fingerprinting","device intelligence","device reputation"]}},Re=e({A0030:()=>He,default:()=>Fe}),He={title:"Business-Level Honeypot",definition:"A fake business resource system built specifically for attackers rather than normal users.",description:"This resource system should ensure that it will not be accessed by normal users during normal business access or request processes, but can be discovered and accessed by attackers through resource ID enumeration, reverse engineering, packet capture, cracking, and other methods. Any access to the fake business resource system is therefore from an attacker. This serves two purposes: first, it immediately alerts the business that a resource has been targeted and attacked; second, it enables continuous tracking of the attacker's identity, characteristics, and behavior to facilitate countermeasure upgrades or related handling.",limitation:"Completely ineffective against attack behavior that perfectly simulates normal user access.",references:[{title:"Guide to Intrusion Detection and Prevention Systems - NIST SP 800-94",link:"https://csrc.nist.gov/pubs/sp/800/94/final"},{title:"MITRE D3FEND: Connected Honeynet Technique"}],keywords:["honeypot","decoy account","canary resource"]},Fe={A0030:He},We=e({A0031:()=>Ee,default:()=>Le}),Ee={title:"Return Fake Data (Data Poisoning)",definition:"Returning inaccurate or fake data to identified attackers.",description:"Also called 'data poisoning.' Returning fake data is typically aimed at scraping of price, review count, sales volume, inventory, and other data. Since price data is widely used by price comparison websites or competitors for unfair competition, returning fake data will render such attempts ineffective. Review counts and sales volumes combined with prices can be used to infer a company's GMV and assess its business performance, which may be used for malicious stock market manipulation or short selling. Returning fake data will make such calculations inaccurate.",limitation:"Returning fake data must only be used when the accuracy of identifying malicious requests is 100%. If fake data is accessed by a normal user, the minor consequence is causing confusion for the user; the more serious consequence is that it could be used as evidence that the platform fabricates data and does not comply with lawful business operations. The lesser impact is negative public opinion; the greater impact may lead to compliance issues.",references:[{title:"Artificial Intelligence Risk Management Framework - NIST AI 100-1",link:"https://www.nist.gov/itl/ai-risk-management-framework"}],keywords:["anti-scraping fake data","scraper poisoning","price scraping defense"]},Le={A0031:Ee},Be=e({A0032:()=>Ne,default:()=>Ge}),Ne={title:"Data Parsing Interference",definition:"Increasing the difficulty for programs to parse or understand the content of obtained data.",description:"Common data parsing interference methods include: text obfuscation, response data encryption (A022-003), dynamic page rendering, JS obfuscation, and returning fake data (A031). Text obfuscation further includes CSS offset, image-disguised text, and custom fonts. These methods do not directly identify or block attackers' data request processes, but instead increase the difficulty for programs to understand data resources, thereby raising the adversarial level.",limitation:"Any resource displayed on a terminal, no matter how complex the countermeasures, can potentially be reversed and cracked. Additionally, there is a very simple and brute-force method that can bypass most data parsing interference: simulate user requests, access the page containing the resource, take a screenshot, and use OCR to identify the resource content — this can easily bypass the methods mentioned above.",references:[{title:"Introduction to Crawlers and Anti-Crawling Techniques (see Chapter 2 - Anti-Crawling Technologies)"}],keywords:["parser evasion","anti-scraping obfuscation","response obfuscation"]},Ge={A0032:Ne},Ue=e({A0033:()=>_e,default:()=>je}),_e={title:"Single-Device Login",definition:"Allowing an account to be logged in only once on the same type of device.",description:"Same-type devices refer to: browsers, mobile APPs, tablets, mini-programs, etc. An account is only allowed to be logged into one browser, mobile APP, tablet, or mini-program instance at a time. When a second same-type device attempts to log in, the previously logged-in corresponding device instance is logged out. This prevents a single account from being logged into multiple same-type devices simultaneously.",limitation:"The detection mechanism for single-device login typically records the number of logins on the same type of device on the server side and resets the previous instance or logs it out when the count exceeds 1. However, this mechanism has a problem: in the case of credential reuse (R0035), i.e., cookie-based login (AT0030), since both the previous device and the new device use the same login instance, the restriction can be bypassed to achieve multi-point login. In this case, a credential reuse detection mechanism needs to be added.",references:[{title:"Digital Identity Guidelines: Authentication and Lifecycle Management - NIST SP 800-63B",link:"https://pages.nist.gov/800-63-3/sp800-63b.html"}],keywords:["one-device login","device-bound login","single-session login"]},je={A0033:_e},Ke=e({A0034:()=>Ve,default:()=>Je}),Ve={title:"Data Obfuscation",definition:"A privacy protection technique that transforms, perturbs, or replaces sensitive data to reduce the risk of data leakage while maintaining a certain level of data usability. The goal is to reduce the risk of identifying sensitive information during data processing and sharing.",description:"Methods include: substitution and replacement — replacing certain values in the original data with vague or fictitious values, such as replacing real names with randomly generated names. Perturbation — introducing noise or perturbation into the data to make it difficult to accurately restore the original values, such as adding random numbers to numerical data. Generalization — reducing specific details to a more general form to protect privacy, such as generalizing a specific address to the city level. Desensitization — removing or replacing sensitive information in the data to protect privacy. Data masking — using masking techniques to hide part of the data, showing only a portion of the information to limit access to sensitive information.",limitation:"Although data obfuscation plays an important role in privacy protection, its use also has some limitations. First, obfuscation may cause information loss, affecting the precision and detail of the original data and thus impacting data analysis and mining effectiveness. Second, some complex obfuscation techniques may introduce significant performance overhead, increasing computational and storage costs. Additionally, excessive data obfuscation may cause data usability issues, reducing the practical value of data for users or analysts. Finally, although intended to protect privacy, some obfuscation techniques may still be subject to attacks that restore data or infer sensitive information, further increasing the factors that need to be carefully weighed when using data obfuscation.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"}],keywords:["data masking","data perturbation","data redaction"]},Je={A0034:Ve,"A0034-001":{title:"Numerical Obfuscation",definition:"Applying a certain degree of obfuscation and approximation to precise numerical values to create a significant difference from the exact values.",description:"The purpose of numerical obfuscation is to prevent attackers from obtaining precise numerical values through data analysis and data mining. For example, many third-party organizations scrape precise product sales volumes and prices to estimate a company's annual revenue and profit, gaining a first-mover advantage in securities trading or corporate mergers and acquisitions. Numerical obfuscation methods include: rounding, truncation, modulo, arithmetic operations, random numbers, etc. Application scenarios include: prices, inventory, sales volumes, ratings, review counts, etc.",limitation:"The goal of numerical obfuscation is to allow data viewers to see the general trend of data without seeing precise values, while preventing third-party organizations from grasping the company's exact operational status. This goal is inherently contradictory, because even without precise data, the final operational status can be estimated from the general trend. Therefore, this defense approach is only suitable for scenarios where the goal is to prevent third-party organizations from obtaining precise operational data.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"}],keywords:["numeric masking","value rounding","value bucketing"]},"A0034-002":{title:"Numerical Indexing",definition:"Converting precise numerical values into an indexed form to create a significant difference from the exact values.",description:"Numerical indexing refers to expressing linear values in a non-linear way through a certain algorithm. The goal is to allow data viewers to see the general trend without seeing precise values, while preventing third-party organizations from grasping the company's exact operational status. Methods include: exponential transformation, logarithmic transformation, squaring, square root, cubing, cube root, etc.",limitation:"Given a certain number of real values, it may be possible to reverse-engineer the indexing algorithm by comparing the generated corresponding indices. Therefore, when indexing, either completely hide the real values to prevent reverse-engineering, or use a stepped algorithm to make the index a stepped curve where each segment uses a different algorithm, making reverse-engineering more difficult.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"}],keywords:["ordinal encoding","numeric binning","value mapping"]},"A0034-003":{title:"Response Status Obfuscation",definition:"Obfuscating precise response statuses so that specific states cannot be distinguished.",description:"For example, many login systems display 'username or password incorrect' when a user fails to log in, allowing attackers to determine whether a user exists on the platform. After obfuscating the response status, whether the user does not exist or the password is wrong, the message 'username or password incorrect' is displayed, preventing attackers from inferring whether the user does not exist or the password is wrong.",limitation:"Response status obfuscation is a relatively basic countermeasure that is well worth trying, but it is not a silver bullet.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"}],keywords:["status code masking","error code obfuscation","response masking"]}},Qe=e({A0035:()=>Xe,default:()=>Ze}),Xe={title:"Data Desensitization (Masking)",definition:"Removing or replacing sensitive information in data with special symbols.",description:"Data desensitization is a technical measure used to protect the security and privacy of sensitive data. The basic principle is to use desensitization algorithms to obscure or transform sensitive data, reducing its sensitivity level before releasing it externally or making it available for access. Methods include static data desensitization — a one-time processing of the original data's sensitive fields to reduce data sensitivity and personal privacy risk — and dynamic data desensitization, which processes data in real time during use to protect private information.",limitation:"Data desensitization may have the following limitations: first, due to insufficient protection of sensitive data, malicious attackers can combine background information to infer sensitive data, creating privacy leakage risks; second, existing desensitization techniques typically alter the original data structure, affecting data accuracy to some extent.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"},{title:"NIST SP 800-188: De-Identifying Government Datasets - Techniques and Governance"}],keywords:["data masking","data redaction","de-identification"]},Ze={A0035:Xe,"A0035-001":{title:"Sensitive Data Removal",definition:"Removing sensitive information from data.",description:"Unlike data desensitization (A035), sensitive data removal refers to removing sensitive information from data rather than replacing it with special symbols. The basic principle is to use removal algorithms to obscure or transform sensitive data, reducing its sensitivity level before releasing it externally or making it available for access. Methods include static data removal and dynamic data removal.",limitation:"Sensitive data removal depends on the execution of data classification and grading, as well as the ability to identify sensitive data. If data classification is inaccurate or the ability to identify sensitive data is insufficient, the effectiveness of sensitive data removal will be poor. Additionally, static sensitive data removal may affect data completeness, availability, and accuracy.",references:[{title:"Guide to Protecting the Confidentiality of Personally Identifiable Information - NIST SP 800-122",link:"https://csrc.nist.gov/pubs/sp/800/122/final"}],keywords:["data redaction","PII removal","sensitive field stripping"]},"A0035-002":{title:"User Information Tokenization",definition:"Converting users' sensitive information into tokens.",description:"User information tokenization is a privacy protection and security enhancement practice. A token is a string that represents specific information or permissions without directly containing sensitive data. This approach helps reduce risk when processing user data, especially in network communication and storage.",limitation:"Tokenization is not applicable to all scenarios. In some applications, direct access to the user's original data is required rather than processing through tokens.",references:[{title:"Information Supplement: Tokenization Product Security Guidelines - PCI SSC",link:"https://www.pcisecuritystandards.org/documents/Tokenization_Product_Security_Guidelines.pdf"}],keywords:["PII tokenization","identity tokenization","tokenized user data"]},"A0035-003":{title:"Virtual Phone Number",definition:"Replacing the user's real phone number with a virtual phone number during order fulfillment.",description:"Virtual phone numbers allow the other party in a transaction to communicate with the user through the virtual number without knowing the user's real phone number. Application scenarios include: transactions, delivery, customer service, complaints, and after-sales. Starting in 2025, China's MIIT launched the 700-number range privacy protection service pilot, replacing platform-built virtual numbers with a dedicated number range that features high identifiability, unified regulation, and three-element binding (user, service provider, session cycle), further standardizing privacy protection number services.",limitation:"Due to the limited number of available virtual numbers, tokens must be used to map multiple user phone numbers to a single virtual number, increasing the cost of calls. Virtual numbers are not friendly for SMS sending and receiving — for example, parcel lockers do not support virtual numbers, preventing consumers from receiving pickup codes. Additionally, some enterprises use mobile phone numbers as intermediary numbers for bulk commercial marketing calls or even fraud under the guise of user privacy protection. The introduction of the 700 dedicated number range helps address this issue, but industry regulation is still being improved.",references:[{title:"Personal Information Protection Law of the People's Republic of China",link:"https://www.samr.gov.cn/wljys/gzzd/art/2023/art_3ef1e889c1e644d4b65b5f5c7f432386.html"}],keywords:["disposable phone number","proxy number","masked phone number"]}},Ye=e({A0036:()=>$e,default:()=>ei}),$e={title:"Resource ID Encryption",definition:"Encrypting resource IDs so that attackers cannot directly enumerate all resource IDs.",description:"Processing resource IDs with encoding techniques so that attackers cannot access resources by incrementing or randomly enumerating resource IDs. Common encoding methods include: random character generation, encryption, and hashing.",limitation:"When choosing an encoding algorithm, ensure it cannot be guessed — for example, using timestamps as IDs, using guessable hash algorithms, or using brute-force-enumerable algorithms. Once the algorithm is guessable, this countermeasure loses its meaning. Additionally, encryption and hash algorithms must be protected against insider leaks and theft, because once leaked, the protection is permanently invalidated. Therefore, either ensure the confidentiality of the algorithm, or use random character generation as a better approach.",references:[{title:"Recommendation for Key Management - NIST SP 800-57 Part 1 Rev. 5",link:"https://csrc.nist.gov/pubs/sp/800/57/pt1/r5/final"}],keywords:["opaque identifiers","encrypted identifiers","hashids"]},ei={A0036:$e},ii=e({A0037:()=>ti,default:()=>ni}),ti={title:"Access Source Tracking",definition:"Tracking the access source of resources to determine the reliability and reasonableness of the source.",description:"Common source tracking checks the Referer header in resource requests. However, there are now more sophisticated approaches: one is to generate encrypted access tokens with time-based, random, and unique properties in the pre-access page for in-site resource access to track resource access; the other is to embed the sharer's identity information as an access token in the shared link when resources are shared off-site. This way, both in-site and off-site resource access can be tracked, enabling identification and blocking of abnormal sources.",limitation:"Two foreseeable breakable scenarios are: 1. For in-site access, attackers can obtain in-site resource access tokens by bulk-constructing resource pre-access pages. 2. For off-site access, in high-traffic scenarios such as advertising and promotion, it is difficult to determine whether token acquisition is non-compliant based on volume alone. For scenario 1, the pre-access page can be included in the tracking coverage, or the randomness of resources in the pre-access page can be increased to prevent targeted resource access. For scenario 2, the off-site resource access ID can be encoded to decouple it from targeted in-site resource access.",references:[{title:"Authorization Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html"}],keywords:["referer tracking","source attribution","access source tracing"]},ni={A0037:ti},ai=e({A0038:()=>oi,default:()=>si}),oi={title:"Proxy Detection",definition:"Detecting the use of proxies when users request network resources.",description:"Proxy detection primarily analyzes the data characteristics of user requests to identify and assess the use of network proxies and terminal proxies, further confirming whether the request is from a real user.",limitation:"The biggest problem with proxy detection is that normal users may also use proxies, making false positives easy.",references:[{title:"Proxy Server - Wikipedia"}],keywords:["anonymous proxy detection","proxy fingerprinting","VPN detection"]},si={A0038:oi,"A0038-001":{title:"Web Access Proxy Detection",definition:"Detecting the access proxy used when users request resources (a typical access proxy is a web browser).",description:"Black-gray industry actors may use non-standard web access proxies to request resources, such as headless browsers, curl, wget, or HTTP libraries from various programming languages. Detection methods include: User-Agent analysis, JavaScript environment detection, JA3 fingerprinting, HTTP/2 fingerprinting, etc.",limitation:"Because web access proxy detection ultimately relies on analyzing terminal request information, placing this measure in a high-adversarial context makes it easy to bypass by forging and modifying data.",references:[{title:"Proxy, Technique T1090 - MITRE ATT&CK",link:"https://attack.mitre.org/techniques/T1090/"}],keywords:["HTTP proxy detection","forward proxy detection","proxy header check"]},"A0038-002":{title:"Network Proxy Detection",definition:"Detecting whether users are using a network proxy when requesting resources.",description:"Common network proxy methods include VPN, SOCKS5, and HTTP proxies. Current common network proxy detection methods include: IP intelligence, request IP clustering, IP attribute analysis, TCP/IP fingerprinting, DNS server location discrepancy, using WebRTC to expose the real IP, and leveraging the network latency characteristics of proxies to determine whether a network proxy is being used.",limitation:"Network proxy detection has the following limitations: first, normal users may also use network proxies, making false positives easy; second, using mobile carrier egress IPs as proxies makes blocking difficult even when detected; third, using ADSL dial-up networks as proxies allows immediate switching to a new proxy by re-dialing after being blocked.",references:[{title:"Proxy, Technique T1090 - MITRE ATT&CK",link:"https://attack.mitre.org/techniques/T1090/"}],keywords:["SOCKS proxy detection","VPN detection","network proxy check"]}},ri=e({A0039:()=>ci,default:()=>li}),ci={title:"Data Hiding",definition:"Hiding data needed by terminal security capabilities to increase the difficulty for attackers to discover and obtain it.",description:"Unlike response data encryption (A022-003), the goal of data hiding is to make attackers unaware of the existence of the data itself, or to know it exists but be unable to find where it is. Some typical data hiding techniques include: algorithm whitebox protection — the goal is to maintain the security of an encryption algorithm even when the encryption key is embedded in the application; steganography — hiding information within other media using a certain algorithm, such as hiding text within an image; virtualization technology — compiling information into specific bytecode to be executed in a custom bytecode interpreter, etc.",limitation:"The core adversarial point of data hiding is the reverse-engineering threshold and time cost caused by information asymmetry. Once the hiding method is discovered, cracking is only a matter of time. Therefore, data hiding typically employs dynamic algorithms or a 'hide-and-seek' mechanism: dynamic algorithms strengthen protection by issuing new algorithms and invalidating old ones before the old algorithm is reverse-engineered; 'hide-and-seek' strengthens protection by moving hidden data from its original location to a new location before it is found.",references:[{title:"Steganography, Technique T1027.003 - MITRE ATT&CK",link:"https://attack.mitre.org/techniques/T1027/003/"}],keywords:["hidden data","data cloaking","stealth data"]},li={A0039:ci},di=e({A0040:()=>ui,default:()=>mi}),ui={title:"Certificate Pinning (SSL Pinning)",definition:"Pinning the server's SSL certificate in the client.",description:"Also known as SSL Pinning. Certificate pinning is a protective measure that pins the server's SSL certificate in the client, preventing attackers from intercepting and modifying network traffic via a man-in-the-middle attack.",limitation:"Certificate pinning is an effective defense mechanism against man-in-the-middle attacks, aimed at raising the bar for MITM attacks. However, attackers can bypass SSL Pinning by using frameworks like Frida or Xposed to hook certificate verification functions, or by replacing the embedded certificate in the application and repackaging it. Additionally, bypassing is easier on jailbroken or rooted devices, and there are now multiple automated tools that can achieve one-click SSL Pinning bypass.",references:[{title:"MASTG-TEST-0244: Missing Certificate Pinning in Network Traffic - OWASP",link:"https://mas.owasp.org/MASTG/tests/android/MASVS-NETWORK/MASTG-TEST-0244/"}],keywords:["TLS pinning","public key pinning","certificate trust pinning"]},mi={A0040:ui},hi=e({A0041:()=>gi,default:()=>pi}),gi={title:"Access Control",definition:"A security management strategy designed to ensure that only authorized and authenticated individuals or entities can enter, connect to, or use systems, networks, applications, or resources. The purpose is to restrict access to sensitive information and critical systems to reduce potential threats and risks.",description:"Access control covers multiple aspects including: authentication — confirming the identity of a user or device to ensure the claimed identity is legitimate and accurate. Authorization — granting authenticated individuals or entities specific permissions to perform certain operations or access certain resources. Access level control — determining the resources, areas, or functions that users or devices can access and setting corresponding permissions. Compliance checks — ensuring users or devices meet the compliance standards and policies specified by the organization or system. Device health checks — verifying that devices connecting to the network meet predefined security standards, including whether they have the latest security patches and antivirus software.",limitation:"Access control focuses on static management of authentication and access permissions and is difficult to adapt to dynamically changing environments and threats. It is also relatively difficult to detect and respond to potential malicious behavior by internal threats or already-authenticated users. Additionally, maintaining complex access policies and rules may increase management and operational complexity, leading to misjudgments or excessive restrictions. Finally, traditional access control may not be flexible enough for modern work environments such as mobile devices and remote work. Organizations implementing access control need to consider these limitations comprehensively and combine other security strategies and technologies to improve overall security.",references:[{title:"Access Control Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Access_Control_Cheat_Sheet.html"}],keywords:["authorization","access management","permission control"]},pi={A0041:gi},fi=e({A0042:()=>yi,default:()=>bi}),yi={title:"Feature Randomization",definition:"Randomizing business features so that attackers cannot complete automated operations through a fixed workflow.",description:"Attackers typically complete automated operations by locating feature points and reproducing business workflows. By randomizing the locating attributes of feature points, or inserting some random events into the business workflow, the attacker's fixed automated workflow can be invalidated.",limitation:"Feature randomization is highly intrusive to the business and requires strong security-business collaboration to implement. Additionally, changes to features may lead to a degraded user experience.",references:[{title:"Authorization Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html"}],keywords:["workflow randomization","anti-bot workflow","interaction randomization"]},bi={A0042:yi,"A0042-001":{title:"DOM Randomization",definition:"Randomizing the DOM structure so that attackers cannot locate and manipulate page elements through the DOM structure.",description:"By randomizing the DOM structure and attributes — such as the DOM tree, element IDs, and class names — attackers cannot locate and manipulate page elements via XPath, ID, class, etc.",limitation:"DOM randomization is ineffective against attack methods that use OCR to identify and manipulate page elements.",references:[{title:"Authorization Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html"}],keywords:["DOM obfuscation","randomized DOM","element shuffling"]},"A0042-002":{title:"Random Event Workflow",definition:"Inserting random events into the normal business workflow so that attackers cannot complete automated operations through a fixed workflow.",description:"Random event workflows are generally targeted at business scenarios with fixed sequential steps. For example, inserting random CAPTCHAs, random questions, random ad pop-ups, or random red packet pop-ups between normal steps to interrupt and interfere with the normal business workflow, invalidating the attacker's pre-recorded automation.",limitation:"Attackers can bypass this type of defense by continuously enumerating random events and alerting on automation workflow exceptions.",references:[{title:"Authorization Cheat Sheet - OWASP",link:"https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html"}],keywords:["random event injection","challenge step","human verification step"]}},vi=e({A0043:()=>wi,default:()=>ki}),wi={title:"Contractual Clause Restrictions",definition:"Adding clauses to contracts that can limit the compliance of risk generation and reduce the probability of risk occurrence.",description:"For example, setting breach of contract liability, breach penalties, and breach compensation.",limitation:"The prerequisite for modifying contract clauses is that both parties to the contract are legal entities, and the modification must comply with laws and regulations. The goal is to restrict the attacker's legal behavior, not to prevent the attacker's malicious behavior.",references:[{title:"Civil Code of the People's Republic of China",link:"https://www.gov.cn/xinwen/2020-06/01/content_5516649.htm"}],keywords:["contract clauses","liquidated damages clause","penalty clause"]},ki={A0043:wi},Ai=e({A0044:()=>Si,default:()=>Pi}),Si={title:"Legal Action",definition:"Taking legal measures to combat attackers.",description:"Legal action is both an effective means of stopping ongoing harm and a deterrent through publicizing the results of enforcement. Currently, criminal statutes related to cybercrime include: Article 285 'Unauthorized Access to Computer Information Systems,' Article 286 'Destruction of Computer Information Systems,' Article 287 'Assisting in Information Network Crimes,' Article 253 'Infringement of Citizens' Personal Information,' Article 219 'Infringement of Trade Secrets,' etc. Additionally, Article 255 'Illegal Business Operations' and Article 217 'Copyright Infringement,' while not cybercrime-specific statutes, are frequently used in cybercrime convictions.",limitation:"The prerequisites for legal action are: 1. There must be illegal or criminal facts that can be referenced against legal statutes; 2. The attacker must be locatable and apprehensible; 3. Criminal evidence and the amount of criminal proceeds must be fixable. For example, web scraping is a common violation that enterprises deeply resent, but there is no specific criminal basis for scraping in the statutes. Scraping only meets the conditions for legal action when it involves: breaking into a system (285), causing a system to malfunction (286), obtaining a certain amount of users' personal information (253), providing paid scraping services to others (255), etc., and when the criminal amount can be very accurately determined, non-criminal amounts distinguished, and the suspect can be located and apprehended within the jurisdiction.",references:[{title:"Criminal Law of the People's Republic of China",link:"https://www.gov.cn/guoqing/2021-10/29/content_5647620.htm"},{title:"Translation: Cybersecurity Law of the People's Republic of China ..."}],keywords:["litigation","legal recourse","cease and desist"]},Pi={A0044:Si},Ti=e({A0045:()=>Ii,default:()=>Ci}),Ii={title:"Privacy Computing",definition:"A collection of technologies that enable data analysis and computation while ensuring the data itself is not exposed externally, achieving the goal of data being 'usable but invisible.'",description:"Privacy computing employs multiple methods to protect user data privacy, including homomorphic encryption, secure multi-party computation, differential privacy, zero-knowledge proofs, searchable encryption, fully homomorphic encryption, and blockchain with smart contracts. Homomorphic encryption allows computation on encrypted data; secure multi-party computation ensures privacy in collaborative computations; differential privacy prevents inference of individual data by introducing noise; zero-knowledge proofs allow verifying the truth of a statement without revealing other information. Searchable encryption enables searching over encrypted data; fully homomorphic encryption provides more flexible homomorphic computation; and blockchain with smart contracts enable decentralized privacy protection. These methods can be combined based on different application requirements to meet diverse privacy protection needs.",limitation:"The limitations of privacy computing include performance overhead, reduced accuracy, communication overhead, complexity, security dependencies, compliance issues, and selective disclosure. It must be applied carefully with consideration for balancing privacy protection against other aspects.",references:[{title:"Privacy-Enhancing Cryptography - NIST Privacy Engineering Program",link:"https://www.nist.gov/itl/applied-cybersecurity/privacy-engineering/collaboration-space/focus-areas/privacy-enhancing"},{title:"Privacy-Preserving Computation: Concepts, Frameworks, and Future Development Trends"}],keywords:["privacy-preserving computation","secure computation","PETs"]},Ci={A0045:Ii},xi=e({A0046:()=>Di,default:()=>qi}),Di={title:"Credit Level Restriction",definition:"Rating users by credit score and applying different restrictions based on their credit level.",description:"Credit grading applies different restrictions to users based on their credit level. For example, users with a high credit rating may enjoy more privileges, while users with a low credit rating enjoy fewer. The goal is to deter malicious behavior and incentivize users to improve their credit standing. Methods include behavior-based, attribute-based, relationship-based, and evaluation-based credit grading.",limitation:"Credit analysis relies on the platform's collection and analysis of user behavior, attributes, relationships, and evaluations, so it cannot identify new high-quality users and may to some extent reduce the motivation of new high-quality users.",references:[{title:"SAMR Opinions on Enterprise Credit Risk Classification Management",link:"https://www.samr.gov.cn/zw/zfxxgk/fdzdgknr/xyjgs/art/2023/art_2fef7a7b24dd4b20b89e942ec8a41880.html"}],keywords:["credit scoring","reputation scoring","trust score restrictions"]},qi={A0046:Di},Mi=e({A0047:()=>zi,default:()=>Oi}),zi={title:"Security Deposit Mechanism",definition:"Also known as a deposit or earnest money, this requires users to pay a certain amount as collateral when using platform services, which may be forfeited upon breach of contract.",description:"A deposit (also called a security deposit or risk margin in practice) is an amount agreed upon by both parties, paid by the debtor or a third party to the creditor as a guarantee of performance. When the obligation is fulfilled, the deposit is returned or offset; when the obligation is not fulfilled, the creditor has priority claim to the funds. The party paying the deposit is called the depositor, generally the debtor or a third party. The party receiving the deposit is called the depositee, who is the creditor.",limitation:"If the deposit amount is too large it will dampen user motivation; if too small it will reduce the deterrent effect. A careful trade-off is required.",references:[{title:"Civil Code of the People's Republic of China",link:"https://www.gov.cn/xinwen/2020-06/01/content_5516649.htm"}],keywords:["deposit guarantee","earnest money","performance bond"]},Oi={A0047:zi},Ri=e({A0048:()=>Hi,default:()=>Fi}),Hi={title:"Complaint and Reporting Channel",definition:"A channel or mechanism provided to users for submitting complaints, reports, or feedback about issues.",description:"Such channels are typically designed to help users resolve problems encountered while using services or purchasing goods, and also help maintain social order and regulate industry behavior.",limitation:"Detection of violations depends on user reports, and user reports may be inaccurate.",references:[{title:"Interim Measures for Handling Market Regulation Complaints and Reports",link:"https://www.samr.gov.cn/zw/zfxxgk/fdzdgknr/fgs/art/2023/art_5d99830d6d864afcafb86cd50ff44ea1.html"}],keywords:["whistleblower hotline","complaint hotline","reporting hotline"]},Fi={A0048:Hi},Wi=e({A0049:()=>Ei,default:()=>Li}),Ei={title:"Digital Watermark/Text Watermark",definition:"Embedding specific information into digital signals — including text, audio, files, images, or video — for copyright protection, integrity verification, copy prevention, or traceability tracking",description:"Also known as a digital watermark. When a watermarked signal is copied, the embedded information is copied along with it. Digital watermarks can be divided into visible and invisible types. Visible watermarks contain information that can be seen while viewing an image or video. Invisible watermarks are added to audio, images, or video as digital data but cannot normally be seen. In general, visible watermarks are primarily used for deterrence and copyright declaration; invisible watermarks are primarily used for traceability and copyright determination.",limitation:"Watermarks may disappear or become unrecoverable when the digital signal is edited, such as through image cropping, video editing, or audio editing.",references:[{title:"Digital watermarking and steganography - NIST DADS",link:"https://xlinux.nist.gov/dads/HTML/digitalWatermark.html"},{title:"C2PA Specification: Content Credentials for Media Provenance and Integrity"}],keywords:["digital watermarking","invisible watermark","watermarking"]},Li={A0049:Ei,"A0049-001":{title:"Text Watermark",definition:"Adding invisible or imperceptible information to text content to verify document authenticity, protect intellectual property, or manage digital rights.",description:"Text watermarks can be visible — for example, replacing certain digits, letters, or symbols with homoglyphs — or invisible, such as inserting invisible characters like Unicode control characters into the text.",limitation:"The limitations of text watermarking include visibility issues, ease of removal, inapplicability to all text types, stealth requirements, inability to prevent copying, inapplicability to encrypted text, difficulty scaling to large deployments, and legal and privacy concerns.",references:[{title:"JD.Army Open Source Text Watermark Solution"}],keywords:["invisible text watermark","text watermarking","character-level watermark"]}};export{ae as A,x as B,Te as C,he as D,fe as E,U as F,h as G,A as H,B as I,a as J,d as K,W as L,Y as M,Q as N,de as O,K as P,R,xe as S,ve as T,v as U,T as V,f as W,i as Y,Ue as _,Ti as a,Re as b,fi as c,ri as d,ai as f,Ke as g,Qe as h,xi as i,ie as j,re as k,hi as l,Ye as m,Ri as n,Ai as o,ii as p,r as q,Mi as r,vi as s,Wi as t,di as u,Be as v,Ae as w,Me as x,We as y,M as z};